$_tipsdb['CGIPriority'] = new DAttrHelp("Priorité CGI", 'Spécifie la priorité du processus d’application externe. La valeur va de <span class=&quot;lst-inline-token lst-inline-token--value&quot;>-20</span> à <span class=&quot;lst-inline-token lst-inline-token--value&quot;>20</span>. Un nombre plus bas signifie une priorité plus élevée.<br/><br/>Un processus CGI ne peut pas avoir une priorité supérieure à celle du serveur web. Si cette priorité est définie sur un nombre inférieur à celle du serveur, la priorité du serveur sera utilisée pour cette valeur.', '', 'entier', '');

$_tipsdb['CPUHardLimit'] = new DAttrHelp("Limite stricte CPU (secs)", 'Spécifie la limite maximale de temps de consommation CPU en secondes pour un processus CGI. Si le processus continue à consommer du temps CPU et atteint la limite stricte, il sera tué de force. Le réglage par défaut du système d’exploitation sera utilisé si la valeur est absente ou définie sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>.', '', 'Nombre entier', '');

