$_tipsdb['ip2locDBFile'] = new DAttrHelp("Chemin du fichier DB IP2Location", 'Emplacement d’un fichier de base de donnees valide.', '', 'Nom de fichier pouvant être un chemin absolu ou un chemin relatif à $SERVER_ROOT.', '');

$_tipsdb['javaServletEngine'] = new DAttrHelp("Moteur Servlet", 'Indique le nom du moteur servlet qui sert cette application web. Les moteurs servlet doivent etre definis dans la section &quot;Applications externes&quot; au niveau serveur ou hote virtuel.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['javaWebAppContext'] = new DAttrHelp("Contexte d'application web Java", 'Beaucoup de personnes executant des applications Java utilisent egalement le moteur de servlets pour servir du contenu statique. Toutefois, aucun moteur de servlets n&#039;est aussi efficace que LiteSpeed Web Server pour ces operations. Pour ameliorer les performances globales, LiteSpeed Web Server peut etre configure comme serveur passerelle: il sert le contenu statique et transfere les requetes de pages Java dynamiques au moteur de servlets.<br/><br/>LiteSpeed Web Server exige que certains contextes soient definis pour executer une application Java. Un contexte d&#039;application web Java cree automatiquement tous les contextes requis a partir du fichier de configuration de l&#039;application web Java (WEB-INF/web.xml).<br/><br/>Gardez ces points a l&#039;esprit lors de la configuration d&#039;un contexte d&#039;application web Java:<br/><ul> <li>Une application externe <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Servlet Engine</span> doit etre configuree dans &quot;Applications externes&quot; avant de creer un contexte d&#039;application web Java.</li> <li>Un &quot;Gestionnaire de scripts&quot; pour les fichiers .jsp doit egalement etre defini.</li> <li>Si l&#039;application web est empaquetee dans un fichier .war, ce fichier doit etre extrait. Le serveur ne peut pas acceder aux archives compressees.</li> <li>Pour les memes ressources, la meme URL doit etre utilisee, que l&#039;acces passe par LiteSpeed Web Server ou par le serveur HTTP integre du moteur de servlets.<br/>Par exemple,   Tomcat 4.1 est installe sous /opt/tomcat. Les fichiers de l&#039;application web &quot;examples&quot;   se trouvent dans /opt/tomcat/webapps/examples/. Via le serveur HTTP integre de Tomcat,   l&#039;application web &quot;examples&quot; est donc accessible avec une URI telle que &quot;/examples/***&quot;.   Le contexte d&#039;application web Java correspondant doit donc etre configure ainsi:   &quot;URI&quot; = <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/examples/</span>, &quot;Emplacement&quot; = <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/opt/tomcat/webapps/examples/</span>.</li>   </ul>', '', '', '');

$_tipsdb['javaWebApp_location'] = new DAttrHelp("Emplacement", 'Indique le repertoire qui contient les fichiers de cette application web. Il s’agit du repertoire contenant &quot;WEB-INF/web.xml&quot;.<br/><br/>Valeur par defaut: $DOC_ROOT + &quot;URI&quot;', '', 'chemin', '');

$_tipsdb['jsonReports'] = new DAttrHelp("Produire des rapports JSON", 'Produit des fichiers de rapport supplementaires au format JSON, avec l’extension .json, dans le repertoire /tmp/lshttpd.<br/><br/>Valeur par defaut: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span>', ' C’est utile pour les developpeurs d’applications qui souhaitent integrer les rapports d’etat et temps reel LiteSpeed dans leurs applications avec les outils standard de traitement JSON integres a la plupart des langages de programmation.', 'Sélectionner avec les boutons radio', 'Lorsque la valeur est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>, des fichiers .status.json et .rtreport.json, .rtreport.2.json, etc. seront crees en plus des fichiers habituels .status et .rtreport, .rtreport.2, etc.');

$_tipsdb['keepAliveTimeout'] = new DAttrHelp("Timeout Keep-Alive (s)", 'Spécifie le temps d’inactivité maximal entre les requêtes d’une connexion keep-alive. Si aucune nouvelle requête n’est reçue pendant cette durée, la connexion sera fermée. Ce réglage ne s’applique qu’aux connexions HTTP/1.1. Les connexions HTTP/2 ont par conception de longs timeouts keep-alive et ne sont pas affectées par ce réglage.', ' Nous recommandons de définir cette valeur juste assez longtemps pour attendre les requêtes suivantes d’un client lorsque d’autres ressources référencées par une même page doivent être chargées. Ne la définissez pas trop longue en espérant que la page suivante sera servie via la connexion keep-alive. Garder de nombreuses connexions keep-alive inactives gaspille les ressources du serveur et pourrait être exploité par des attaques (D)DoS. <span class=&quot;lst-inline-token lst-inline-token--value&quot;>2-5</span> secondes est une plage raisonnable pour la plupart des applications. LiteSpeed est très efficace dans un environnement sans keep-alive.', 'Nombre entier', '');

$_tipsdb['keyFile'] = new DAttrHelp("Fichier de cle privee", 'Nom de fichier de la cle privee SSL. Le fichier de cle ne doit pas etre chiffre.', ' Le fichier de cle privee doit etre place dans un repertoire securise qui autorise un acces en lecture seule a l’utilisateur sous lequel le serveur s’execute.', 'Nom de fichier pouvant être un chemin absolu ou un chemin relatif à $SERVER_ROOT.', '');

$_tipsdb['lbContext'] = new DAttrHelp("Contexte d'équilibrage", 'Comme les autres applications externes, les applications worker de l&#039;equilibreur de charge ne peuvent pas etre utilisees directement. Elles doivent etre associees a une URL au moyen d&#039;un contexte. Un contexte d&#039;equilibreur de charge associe une URI qui sera repartie par les workers de l&#039;equilibreur de charge.', '', '', '');

$_tipsdb['lbapp'] = new DAttrHelp("Load Balancer", 'Indique le nom du load balancer a associer a ce contexte. Ce load balancer est une application virtuelle et doit etre defini dans la section &quot;Applications externes&quot; au niveau serveur ou hote virtuel.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['listenerBinding'] = new DAttrHelp("Liaison", 'Indique a quel processus enfant lshttpd le listener est affecte. Des processus enfants differents peuvent etre utilises pour traiter les requetes adressees a differents listeners en associant manuellement un listener a un processus. Par defaut, un listener est affecte a tous les processus enfants.', '', 'Sélectionner avec des cases à cocher', '');

$_tipsdb['listenerIP'] = new DAttrHelp("Adresse IP", 'Indique l&#039;adresse IP de ce listener. Toutes les adresses IP disponibles sont listees. Les adresses IPv6 sont placees entre &quot;[ ]&quot;.<br/><br/>Pour ecouter sur toutes les adresses IPv4, selectionnez <span class=&quot;lst-inline-token lst-inline-token--value&quot;>ANY</span>. Pour ecouter sur toutes les adresses IPv4 et IPv6, selectionnez <span class=&quot;lst-inline-token lst-inline-token--value&quot;>[ANY]</span>.<br/><br/>Pour servir a la fois les clients IPv4 et IPv6, une adresse IPv6 mappee IPv4 doit etre utilisee a la place d&#039;une simple adresse IPv4. Une adresse IPv6 mappee IPv4 s&#039;ecrit [::FFFF:x.x.x.x].', ' Si votre machine a plusieurs IP sur des sous-reseaux differents, vous pouvez selectionner une IP specifique afin de n&#039;autoriser que le trafic provenant du sous-reseau correspondant.', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['listenerModules'] = new DAttrHelp("Modules de listener", 'Les donnees de configuration des modules du listener sont, par defaut, heritees de la configuration des modules du serveur. Les modules du listener sont limites aux hooks TCP/IP de couche 4.', '', '', '');

$_tipsdb['listenerName'] = new DAttrHelp("Nom du listener", 'Un nom unique pour ce listener.', '', '', '');

$_tipsdb['listenerPort'] = new DAttrHelp("Port", 'Indique le port TCP du listener. Seul le superutilisateur (&quot;root&quot;) peut utiliser les ports inferieurs a <span class=&quot;lst-inline-token lst-inline-token--value&quot;>1024</span>. Le port <span class=&quot;lst-inline-token lst-inline-token--value&quot;>80</span> est le port HTTP par defaut. Le port <span class=&quot;lst-inline-token lst-inline-token--value&quot;>443</span> est le port HTTPS par defaut.', '', 'Nombre entier', '');

$_tipsdb['listenerSecure'] = new DAttrHelp("Securise", 'Indique s&#039;il s&#039;agit d&#039;un listener securise (SSL). Pour les listeners securises, des reglages SSL supplementaires doivent etre correctement definis.', '', 'Sélectionner avec les boutons radio', '');

$_tipsdb['lmap'] = new DAttrHelp("Mappages des hôtes virtuels", 'Affiche les mappages actuellement établis depuis un listener particulier vers des hôtes virtuels. Le nom de l&#039;hôte virtuel apparaît entre crochets et est suivi des noms de domaine correspondants pour ce listener.', 'Si un hôte virtuel n&#039;a pas été chargé correctement (erreurs fatales dans la configuration de l&#039;hôte virtuel), le mappage vers cet hôte virtuel ne sera pas affiché.', '', '');

$_tipsdb['lname'] = new DAttrHelp("Nom - Listener", 'Nom unique qui identifie ce listener. Il s&#039;agit du &quot;Nom du listener&quot; que vous avez spécifié lors de la configuration du listener.', '', '', '');

$_tipsdb['location'] = new DAttrHelp("Emplacement", 'Indique l’emplacement correspondant de ce contexte dans le systeme de fichiers.<br/><br/>Valeur par defaut: $DOC_ROOT + &quot;URI&quot;', '', 'Il peut s’agir d’un chemin absolu ou d’un chemin relatif a $SERVER_ROOT, $VH_ROOT ou $DOC_ROOT. $DOC_ROOT est le chemin relatif par defaut et peut etre omis.<br/><br/>Si &quot;URI&quot; est une expression reguliere, la sous-chaine correspondante peut etre utilisee pour former la chaine &quot;Root&quot;. Elle peut etre referencee avec les valeurs &quot;$1&quot; - &quot;$9&quot;. &quot;$0&quot; et &quot;&&quot; peuvent referencer toute la chaine correspondante. Une chaine de requete peut aussi etre definie en ajoutant &quot;?&quot; suivi de la chaine de requete. Attention: &quot;&&quot; doit etre echappe sous la forme &quot;\&&quot; dans la chaine de requete.', 'Une URI simple comme <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/examples/</span>, avec &quot;Emplacement&quot; defini sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/home/john/web_examples</span>, mappe la requete &quot;/examples/foo/bar.html&quot; vers le fichier &quot;/home/john/web_examples/foo/bar.html&quot;.<br/>Pour simuler mod_userdir d’Apache, definissez URI sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>exp: ^/~([A-Za-z0-9]+)(.*)</span>, definissez &quot;Emplacement&quot; sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/home/$1/public_html$2</span>. Avec ces parametres, une requete URI /~john/foo/bar.html sera mappee vers le fichier /home/john/public_html/foo/bar.html.');

$_tipsdb['logUseServer'] = new DAttrHelp("Utiliser le journal du serveur", 'Spécifie si les messages de journal de cet hôte virtuel doivent être placés dans le fichier journal du serveur au lieu de créer son propre fichier journal.', '', 'Sélectionner avec les boutons radio', '');

$_tipsdb['log_compressArchive'] = new DAttrHelp("Compresser l'archive", 'Spécifie s&#039;il faut compresser les fichiers journaux rotatifs afin d&#039;économiser de l&#039;espace disque.', 'Les fichiers journaux se compressent très bien; cette option est recommandée pour réduire l&#039;utilisation du disque par les anciens journaux.', 'Sélectionner avec les boutons radio', '');

$_tipsdb['log_debugLevel'] = new DAttrHelp("Niveau de débogage", 'Spécifie le niveau de journalisation de débogage. &quot;Niveau de journalisation&quot; doit être défini sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span> pour utiliser cette fonction. La journalisation de débogage est désactivée lorsque &quot;Debug Level&quot; est défini sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span>, même si &quot;Niveau de journalisation&quot; est défini sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span>. &quot;Basculer la journalisation de débogage&quot; peut être utilisé pour contrôler le niveau de débogage sur un serveur actif sans redémarrage.', ' Important! Définissez toujours ce paramètre sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span> si vous n&#039;avez pas besoin d&#039;une journalisation de débogage détaillée. Une journalisation de débogage active dégrade fortement les performances du service et peut saturer l&#039;espace disque en très peu de temps. La journalisation de débogage inclut des informations détaillées pour chaque requête et réponse.<br/><br/>Il est recommandé de définir Log Level sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span> et Debug Level sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span>. Ces paramètres évitent de remplir le disque avec des journaux de débogage, tout en permettant d&#039;utiliser l&#039;action &quot;Basculer la journalisation de débogage&quot; pour contrôler la sortie de débogage.', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['log_enableStderrLog'] = new DAttrHelp("Activer le journal stderr", 'Spécifie s&#039;il faut écrire dans le journal lors de la réception d&#039;une sortie stderr provenant de processus démarrés par le serveur.<br/><br/>Si cette option est activée, les messages stderr seront journalisés dans le même répertoire que le journal du serveur avec le nom fixe &quot;stderr.log&quot;. Si elle est désactivée, toute sortie stderr sera ignorée.<br/><br/>Les fonctions comme error_log() de PHP qui n&#039;écrivent pas directement vers stderr (descripteur de fichier 2) ne sont pas affectées par ce paramètre et écriront dans le fichier défini par la directive PHP ini &#039;error_log&#039; ou dans le fichier &quot;error.log&quot; du serveur avec la balise &#039;[STDERR]&#039; si cette directive n&#039;est pas définie.', 'Activez cette option si vous devez déboguer des applications externes configurées, par exemple PHP, Ruby, Java, Python ou Perl.', 'Sélectionner avec les boutons radio', '');

$_tipsdb['log_fileName'] = new DAttrHelp("Nom du fichier", 'Spécifie le chemin du fichier journal.', ' Placez le fichier journal sur un disque séparé.', 'Nom de fichier pouvant être un chemin absolu ou un chemin relatif à $SERVER_ROOT.', '');

$_tipsdb['log_keepDays'] = new DAttrHelp("Jours de conservation", 'Spécifie le nombre de jours pendant lesquels le fichier journal d&#039;accès sera conservé sur le disque. Seuls les fichiers journaux rotatifs plus anciens que le nombre de jours spécifié seront supprimés. Le fichier journal actuel ne sera pas modifié, quel que soit le nombre de jours de données qu&#039;il contient. Si vous ne voulez pas supprimer automatiquement les journaux obsolètes et très anciens, définissez cette valeur sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>.', '', 'Nombre entier', '');

$_tipsdb['log_logLevel'] = new DAttrHelp("Niveau de journalisation", 'Spécifie le niveau de journalisation à inclure dans le fichier journal. Les niveaux disponibles (du plus élevé au plus bas) sont: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>ERROR</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>WARNING</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NOTICE</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>INFO</span> et <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span>. Seuls les messages dont le niveau est supérieur ou égal au paramètre actuel seront journalisés.', ' L&#039;utilisation du niveau de journalisation <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span> n&#039;a pas d&#039;impact sur les performances, sauf si &quot;Niveau de débogage&quot; est défini sur un niveau autre que <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span>. Il est recommandé de définir Log Level sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span> et Debug Level sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span>. Ces paramètres évitent de remplir le disque avec des journaux de débogage, tout en permettant d&#039;utiliser l&#039;action &quot;Basculer la journalisation de débogage&quot; pour contrôler la sortie de débogage.', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['log_rollingSize'] = new DAttrHelp("Taille de rotation (octets)", 'Spécifie quand le fichier journal actuel doit être renouvelé. Lorsque la taille du fichier dépasse la limite de rotation, le fichier journal actif est renommé en log_name.mm_dd_yyyy(.sequence) dans le même répertoire et un nouveau fichier journal actif est créé. La taille réelle du fichier journal rotatif peut être légèrement supérieure à cette limite. Définissez sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span> pour désactiver la rotation des journaux.', 'Ajoutez &quot;K&quot;, &quot;M&quot; ou &quot;G&quot; au nombre pour indiquer kilo-, méga- et giga-octets.', 'Nombre entier', '');

$_tipsdb['loggerAddress'] = new DAttrHelp("Adresse du journaliseur distant (optionnel)", 'Indique l&#039;adresse de socket facultative pour ce journaliseur par tube. Definissez cette valeur lorsque le journaliseur est accessible par un socket reseau ou Unix Domain Socket. Laissez ce champ vide pour un journaliseur par tube local demarre depuis le chemin de commande configure.', '', 'Adresse IPv4:port, nom d&#039;hote:port, [adresse IPv6]:port, UDS://chemin ou unix:chemin', '127.0.0.1:1514<br/>logger.example.com:1514<br/>UDS://tmp/lshttpd/logger.sock');

$_tipsdb['loginHistoryRetention'] = new DAttrHelp("Retention de l'historique de connexion (jours)", 'Indique combien de jours les enregistrements d&#039;historique de connexion sont conserves avant que les anciennes entrees soient supprimees. Valeur par defaut si non definie: 90 jours.', 'Conservez suffisamment d&#039;historique pour l&#039;audit et le diagnostic, mais evitez de conserver plus de donnees que necessaire.', 'Nombre entier', '');

$_tipsdb['loginThrottle'] = new DAttrHelp("Limitation de connexion", 'Configurez la limitation des connexions a la console WebAdmin et la retention des enregistrements associes aux connexions et a l&#039;audit.', '', '', '');

$_tipsdb['lsapiContext'] = new DAttrHelp("Contexte LSAPI", 'Les applications externes ne peuvent pas etre utilisees directement. Elles doivent etre configurees comme gestionnaire de scripts ou associees a une URL au moyen d&#039;un contexte. Un contexte LiteSpeed SAPI associe une URI a une application LSAPI (LiteSpeed Server Application Programming Interface). Des modules LSAPI existent actuellement pour PHP, Ruby et Python. Comme LSAPI est developpe specifiquement pour LiteSpeed web server, c&#039;est le moyen le plus efficace de communiquer avec LiteSpeed web server.', '', '', '');

$_tipsdb['lsapiapp'] = new DAttrHelp("Application LiteSpeed SAPI", 'Indique le nom de l’application LiteSpeed SAPI a connecter a ce contexte. Cette application doit etre definie dans la section &quot;Applications externes&quot; au niveau serveur ou hote virtuel.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['lsrecaptcha'] = new DAttrHelp("Protection CAPTCHA", 'CAPTCHA Protection est un service fourni pour aider a attenuer une forte charge serveur. CAPTCHA Protection s&#039;activera apres l&#039;une des situations ci-dessous. Une fois actif, toutes les requetes des clients NON TRUSTED(tels que configures) seront redirigees vers une page de validation CAPTCHA. Apres validation, le client sera redirige vers la page souhaitee.<br/><br/>Les situations suivantes activeront CAPTCHA Protection:<br/>1. Le nombre de requetes concurrentes du serveur ou du vhost depasse la limite de connexion configuree.<br/>2. Anti-DDoS est active et un client accede a une url d&#039;une maniere suspecte. Le client sera d&#039;abord redirige vers CAPTCHA au lieu d&#039;etre refuse lorsque le declenchement se produit.<br/>3. Un nouvel environnement de regle de rewrite est fourni pour activer CAPTCHA via RewriteRules. &#039;verifycaptcha&#039; peut etre defini pour rediriger les clients vers CAPTCHA. Une valeur speciale &#039;: deny&#039; peut etre definie pour refuser le client s&#039;il a echoue trop de fois. Par exemple, [E=verifycaptcha] redirigera toujours vers CAPTCHA jusqu&#039;a verification. [E=verifycaptcha: deny] redirigera vers CAPTCHA jusqu&#039;a ce que Max Tries soit atteint, apres quoi le client sera refuse.', '', '', '');

$_tipsdb['lstatus'] = new DAttrHelp("État - Listener", 'État actuel de ce listener. L&#039;état est soit <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Running</span>, soit <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Error</span>.', 'Si le listener est dans l&#039;état <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Error</span>, vous pouvez consulter le journal du serveur pour en connaître la raison.', '', '');

$_tipsdb['mappedListeners'] = new DAttrHelp("Listeners mappés", 'Indique les noms de tous les listeners auxquels cette template est mappée. Un mappage listener vers hôte virtuel pour les hôtes virtuels membres de cette template sera ajouté aux listeners indiqués dans ce champ. Ce mappage associera les listeners aux hôtes virtuels selon les noms de domaine et les alias définis dans les configurations individuelles des hôtes virtuels membres.', '', 'liste séparée par des virgules', '');

$_tipsdb['maxCGIInstances'] = new DAttrHelp("Nombre max. d’instances CGI", 'Spécifie le nombre maximal de processus CGI simultanés que le serveur peut lancer. Pour chaque requête vers un script CGI, le serveur doit lancer un processus CGI autonome. Sur un système Unix, le nombre de processus simultanés est limité. Un excès de processus simultanés dégradera les performances de tout le système et constitue une façon de mener une attaque DoS. LiteSpeed Server met en pipeline les requêtes vers les scripts CGI et limite les processus CGI simultanés afin d’assurer des performances et une fiabilité optimales. La limite stricte est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>2000</span>.', ' Une limite plus élevée ne se traduit pas nécessairement par de meilleures performances. Dans la plupart des cas, une limite plus basse donne de meilleures performances et une meilleure sécurité. Une limite plus élevée n’aide que lorsque la latence I/O est excessive pendant le traitement CGI.', 'Nombre entier', '');

$_tipsdb['maxCachedFileSize'] = new DAttrHelp("Taille max. de petit fichier en cache (octets)", 'Spécifie le plus grand fichier statique qui sera mis en cache dans un tampon mémoire préalloué. Les fichiers statiques peuvent être servis de quatre façons différentes: cache de tampon mémoire, cache mappé en mémoire, lecture/écriture simple et sendfile(). Les fichiers dont la taille est inférieure à ce réglage sont servis depuis le cache de tampon mémoire. Les fichiers dont la taille est supérieure à ce réglage, mais inférieure à &quot;Taille max. de fichier MMAP (octets)&quot;, seront servis depuis le cache mappé en mémoire. Les fichiers dont la taille est supérieure à &quot;Taille max. de fichier MMAP (octets)&quot; seront servis via lecture/écriture simple ou sendfile(). Il est optimal de servir les fichiers statiques plus petits que 4K depuis le cache de tampon mémoire.', '', 'Nombre entier', '');

$_tipsdb['maxConnections'] = new DAttrHelp("Connexions max.", 'Spécifie le nombre maximal de connexions simultanées que le serveur peut accepter. Cela inclut les connexions TCP simples et les connexions SSL. Une fois la limite maximale de connexions simultanées atteinte, le serveur fermera les connexions Keep-Alive lorsqu’elles auront terminé les requêtes actives.', 'Lorsque le serveur est démarré par l’utilisateur &quot;root&quot;, il essaiera d’ajuster automatiquement les limites de descripteurs de fichiers par processus; toutefois, si cela échoue, vous devrez peut-être augmenter cette limite manuellement.', 'Nombre entier', '');

$_tipsdb['maxConns'] = new DAttrHelp("Connexions max.", 'Indique le nombre maximal de connexions concurrentes pouvant etre etablies entre le serveur et une application externe. Ce reglage controle combien de requetes peuvent etre traitees simultanement par une application externe; toutefois, la limite reelle depend aussi de l&#039;application externe elle-meme. Augmenter cette valeur n&#039;aidera pas si l&#039;application externe n&#039;est pas assez rapide ou ne peut pas monter en charge avec un grand nombre de requetes concurrentes.', ' Definir une valeur elevee ne se traduit pas directement par de meilleures performances. Fixer la limite a une valeur qui ne surcharge pas l&#039;application externe donnera les meilleures performances/le meilleur debit.', 'Nombre entier', '');

$_tipsdb['maxDynRespHeaderSize'] = new DAttrHelp("Taille max. d’en-tête de réponse dynamique (octets)", 'Spécifie la taille maximale de l’en-tête d’une réponse générée dynamiquement. La limite stricte est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>131072</span> octets ou 128K.<br/><br/>Valeur par défaut: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>32768</span> ou <span class=&quot;lst-inline-token lst-inline-token--value&quot;>32K</span>', ' Définissez ceci raisonnablement bas pour aider à reconnaître les mauvaises réponses générées dynamiquement par des applications externes.', 'Nombre entier', '');

$_tipsdb['maxDynRespSize'] = new DAttrHelp("Taille max. du corps de réponse dynamique (octets)", 'Spécifie la taille maximale du corps d’une réponse générée dynamiquement.', ' Définissez la limite raisonnablement basse pour aider à identifier les mauvaises réponses. Il n’est pas rare que des scripts mal formés contiennent une boucle infinie menant à des réponses de taille infinie.', 'Nombre entier', '');

$_tipsdb['maxKeepAliveReq'] = new DAttrHelp("Requêtes Keep-Alive max.", 'Spécifie le nombre maximal de requêtes pouvant être servies via une session keep-alive (persistante). La connexion sera fermée une fois cette limite atteinte. Vous pouvez également définir cette limite pour chaque virtual host.', ' Définissez une valeur raisonnablement élevée. Une valeur de &quot;1&quot; ou &quot;0&quot; désactivera keep-alive.', 'Nombre entier', '');

$_tipsdb['maxMMapFileSize'] = new DAttrHelp("Taille max. de fichier MMAP (octets)", 'Spécifie le plus grand fichier statique qui sera mappé en mémoire (MMAP). Les fichiers statiques peuvent être servis de quatre façons différentes: cache de tampon mémoire, cache mappé en mémoire, lecture/écriture simple et sendfile(). Les fichiers dont la taille est inférieure à &quot;Taille max. de petit fichier en cache (octets)&quot; sont servis depuis le cache de tampon mémoire. Les fichiers dont la taille est supérieure à &quot;Taille max. de petit fichier en cache (octets)&quot;, mais inférieure à la taille max. de fichier MMAP, seront servis depuis le cache mappé en mémoire. Les fichiers dont la taille est supérieure à la taille max. de fichier MMAP seront servis via lecture/écriture simple ou sendfile(). Comme le serveur possède un espace d’adressage 32 bits (2GB), il n’est pas recommandé de mapper en mémoire de très gros fichiers.', '', 'Nombre entier', '');

$_tipsdb['maxMindDBEnv'] = new DAttrHelp("Variables d’environnement", 'Assigne les resultats des recherches de base de donnees a des variables d’environnement.', '', 'Variable_Name mapped_DB_data<br/><br/>Une entree par ligne. Le chemin vers les donnees peut utiliser des cles de map ou des index de tableau bases sur 0, separes par /.', 'COUNTRY_CODE COUNTRY_DB/country/iso_code<br/>REGION_CODE  CITY_DB/subdivisions/0/iso_code');

$_tipsdb['maxReqBodySize'] = new DAttrHelp("Taille max. du corps de requête (octets)", 'Spécifie la taille maximale du corps d’une requête HTTP. Pour un système d’exploitation 32 bits, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>2GB</span> est la limite stricte. Pour un système 64 bits, elle est virtuellement illimitée.', ' Pour aider à prévenir les attaques DoS, essayez de limiter cette valeur à ce qui est réellement nécessaire. Votre espace de swap doit disposer de suffisamment d’espace libre pour accueillir cette limite.', 'Nombre entier', '');

$_tipsdb['maxReqHeaderSize'] = new DAttrHelp("Taille max. d’en-tête de requête (octets)", 'Spécifie la taille maximale d’un en-tête de requête HTTP, URL de requête incluse. La limite stricte est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>131072</span> octets ou 128K.<br/><br/>Valeur par défaut: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>32768</span> ou <span class=&quot;lst-inline-token lst-inline-token--value&quot;>32K</span>', ' Définissez ceci raisonnablement bas pour réduire l’utilisation mémoire et aider à identifier les fausses requêtes et les attaques DoS.<br/>4-8K est suffisant pour la plupart des sites web dans des circonstances normales.', 'Nombre entier', '');

$_tipsdb['maxReqURLLen'] = new DAttrHelp("Longueur max. d’URL de requête (octets)", 'Spécifie la taille maximale d’une URL de requête. URL est l’adresse texte complète utilisée pour accéder à une ressource serveur, y compris la chaîne de requête. La limite stricte est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>65530</span> octets. Les valeurs plus grandes, comme <span class=&quot;lst-inline-token lst-inline-token--value&quot;>64K</span> (6 octets de plus), seront traitées comme si <span class=&quot;lst-inline-token lst-inline-token--value&quot;>65530</span> avait été utilisé.<br/><br/>Valeur par défaut: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>8192</span> ou <span class=&quot;lst-inline-token lst-inline-token--value&quot;>8K</span>.', ' Définissez ceci raisonnablement bas pour réduire l’utilisation mémoire et aider à identifier les fausses requêtes et les attaques DoS.<br/>2-3K est suffisant pour la plupart des sites web, sauf si la méthode HTTP GET est utilisée avec de grandes chaînes de requête au lieu de POST.', 'Nombre entier', '');

$_tipsdb['maxSSLConnections'] = new DAttrHelp("Connexions SSL max.", 'Spécifie le nombre maximal de connexions SSL simultanées que le serveur acceptera. Comme le total des connexions SSL et non SSL simultanées ne peut pas dépasser la limite spécifiée par &quot;Connexions max.&quot;, le nombre réel de connexions SSL simultanées autorisées doit être inférieur à cette limite.', '', 'Nombre entier', '');

$_tipsdb['memHardLimit'] = new DAttrHelp("Limite stricte mémoire (octets)", 'Semblable à &quot;Limite souple mémoire (octets)&quot;, sauf que la limite souple peut être relevée jusqu’à la limite stricte depuis un processus utilisateur. La limite stricte peut être définie au niveau serveur ou au niveau d’une application externe individuelle. La limite de niveau serveur sera utilisée si elle n’est pas définie au niveau de l’application individuelle.<br/><br/>La valeur par défaut du système d’exploitation sera utilisée si la valeur est absente aux deux niveaux ou définie sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>.', ' N’ajustez pas excessivement cette limite. Cela peut entraîner des erreurs 503 si votre application a besoin de plus de mémoire.', 'Nombre entier', '');

$_tipsdb['memSoftLimit'] = new DAttrHelp("Limite souple mémoire (octets)", 'Spécifie la limite de consommation mémoire en octets pour un processus d’application externe ou une application externe lancée par le serveur.<br/><br/>Le but principal de cette limite est d’empêcher une utilisation excessive de mémoire due à des bugs logiciels ou à des attaques intentionnelles, et non d’imposer une limite à l’usage normal. Veillez à laisser assez de marge; sinon votre application peut échouer et une erreur 503 peut être renvoyée. Elle peut être définie au niveau serveur ou au niveau d’une application externe individuelle. La limite de niveau serveur sera utilisée si elle n’est pas définie au niveau de l’application individuelle.<br/><br/>Le réglage par défaut du système d’exploitation sera utilisé si la valeur est absente aux deux niveaux ou définie sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>.', ' N’ajustez pas excessivement cette limite. Cela peut entraîner des erreurs 503 si votre application a besoin de plus de mémoire.', 'Nombre entier', '');

$_tipsdb['memberVHRoot'] = new DAttrHelp("Racine de l'hôte virtuel membre", 'Indique le répertoire racine de cet hôte virtuel. S&#039;il est laissé vide, la racine d&#039;hôte virtuel par défaut de cette template sera utilisée.<br/><br/>Remarque: ce n&#039;est <b>PAS</b> la racine des documents. Il est recommandé de placer tous les fichiers liés à l&#039;hôte virtuel (comme la configuration de l&#039;hôte virtuel, les fichiers journaux, les fichiers html, les scripts CGI, etc.) sous ce répertoire. La racine de l&#039;hôte virtuel peut être référencée comme $VH_ROOT.', '', 'chemin', '');

$_tipsdb['mime'] = new DAttrHelp("Parametres MIME", 'Indique le fichier contenant les parametres MIME pour ce serveur. Il est toujours relatif a la racine reelle lorsqu’un chemin absolu est donne en mode chroot. Cliquez sur le nom du fichier pour afficher/modifier les entrees MIME detaillees.', 'Cliquez sur le nom du fichier pour modifier les parametres MIME.', 'Nom de fichier pouvant être un chemin absolu ou un chemin relatif à $SERVER_ROOT.', '');

$_tipsdb['mimesuffix'] = new DAttrHelp("Suffixes", 'Vous pouvez lister plusieurs suffixes pour le meme type MIME, en les separant par des virgules.', '', '', '');

$_tipsdb['mimetype'] = new DAttrHelp("Type MIME", 'Un type MIME se compose d’un type et d’un sous-type au format &quot;type/subtype&quot;.', '', '', '');

$_tipsdb['minGID'] = new DAttrHelp("GID minimum", 'Spécifie l’ID de groupe minimum autorisé pour exécuter des applications externes lorsqu’elles s’exécutent comme un groupe spécifié. L’exécution d’un script externe avec un ID de groupe inférieur à la valeur spécifiée ici sera refusée.', ' Définissez-le assez haut pour exclure tous les groupes utilisés par les utilisateurs système.', 'Nombre entier', '');

$_tipsdb['minUID'] = new DAttrHelp("UID minimum", 'Spécifie l’ID utilisateur minimum autorisé pour exécuter des applications externes lorsqu’elles s’exécutent comme un utilisateur spécifié. L’exécution d’un script externe avec un ID utilisateur inférieur à la valeur spécifiée ici sera refusée.', ' Définissez-le assez haut pour exclure tous les utilisateurs système/privilégiés.', 'Nombre entier', '');

$_tipsdb['modParams'] = new DAttrHelp("Paramètres du module", 'Définissez les paramètres du module. Les paramètres du module sont définis par le développeur du module.<br/><br/>La valeur définie au niveau serveur sera assignée globalement comme valeur par défaut. L&#039;utilisateur peut remplacer ce réglage aux niveaux listener, hôte virtuel ou contexte. S&#039;il n&#039;est défini à aucun de ces niveaux, la valeur est héritée du niveau supérieur suivant.', '', 'Spécifiée par l&#039;interface du module.', '');

$_tipsdb['moduleContext'] = new DAttrHelp("Contexte de module", 'Un contexte de gestionnaire de module associe une URI a un module enregistre. Les modules doivent etre enregistres dans l&#039;onglet de configuration des modules du serveur.', '', '', '');

$_tipsdb['moduleEnabled'] = new DAttrHelp("Activer le module", 'Active les hooks du module globalement. Ce réglage peut être remplacé aux niveaux listener et hôte virtuel.<br/><br/>Valeur par défaut: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>', '', 'Sélectionner avec les boutons radio', '');

$_tipsdb['moduleEnabled_lst'] = new DAttrHelp("Activer le module", 'Active les hooks du module au niveau listener. Ce réglage ne prend effet que si le module possède des hooks de niveau TCP/IP (L4_BEGSESSION, L4_ENDSESSION, L4_RECVING, L4_SENDING).<br/><br/>Valeur par défaut: hériter du réglage de niveau serveur', '', 'Sélectionner avec les boutons radio', '');

