$_tipsdb['moduleNameSel'] = new DAttrHelp("Module", 'Nom du module. Le module doit etre enregistre sous l’onglet Server Module Configuration. Une fois enregistre, le nom du module sera disponible dans la liste deroulante pour les configurations Listener et Virtual Host.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['modulename'] = new DAttrHelp("Module", 'Nom d&#039;un module externe ou interne à charger au démarrage du serveur.<br/><br/><b>Externe</b><br/>La valeur utilisée pour les modules externes doit correspondre au nom du fichier &quot;.so&quot; du module sous $SERVER_ROOT/modules/modulename.so afin que l&#039;application serveur puisse le charger. Le serveur doit être redémarré après l&#039;enregistrement d&#039;un nouveau module.<br/><br/><b>Interne</b><br/>La valeur utilisée pour les modules internes doit correspondre au nom de module utilisé lors de la compilation du module. Par exemple, elle doit être définie sur &quot;cache&quot; pour le module de cache interne inclus avec le serveur.', '', 'chaîne', '');

$_tipsdb['namespace'] = new DAttrHelp("Conteneur Namespace", 'Définissez sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Enabled</span> si vous souhaitez lancer les processus CGI (y compris les programmes PHP) dans un sandbox de conteneur namespace. Utilisé uniquement lorsque &quot;Conteneur Bubblewrap&quot; est défini sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Disabled</span>.<br/><br/>Lorsque ce réglage n’est pas <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Disabled</span> au niveau serveur, sa valeur peut être remplacée au niveau virtual host.<br/><br/>Valeurs par défaut:<br/><b>Niveau serveur:</b> <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Disabled</span><br/><b>Niveau virtual host:</b> Hériter du réglage de niveau serveur', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['namespaceConf'] = new DAttrHelp("Fichier de modèle Namespace", 'Chemin vers un fichier de configuration existant contenant une liste de répertoires à monter ainsi que les méthodes utilisées pour les monter. Lorsque &quot;Conteneur Namespace&quot; est défini sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Enabled</span> et que cette valeur n’est pas définie, les réglages de configuration sécurisés par défaut suivants seront utilisés:<br/><br/><span class=&quot;lst-inline-token lst-inline-token--value&quot;> $HOMEDIR/.lsns/tmp /tmp,tmp<br/>/usr,ro-bind<br/>/lib,ro-bind<br/>/lib64,ro-bind-try<br/>/bin,ro-bind<br/>/sbin,ro-bind<br/>/var,dir<br/>/var/www,ro-bind-try<br/>/proc,proc<br/>../tmp var/tmp,symlink<br/>/dev,dev<br/>/etc/localtime,ro-bind-try<br/>/etc/ld.so.cache,ro-bind-try<br/>/etc/resolv.conf,ro-bind-try<br/>/etc/ssl,ro-bind-try<br/>/etc/pki,ro-bind-try<br/>/etc/man_db.conf,ro-bind-try<br/>/usr/local/bin/msmtp /etc/alternatives/mta,ro-bind-try<br/>/usr/local/bin/msmtp /usr/sbin/exim,ro-bind-try<br/>$HOMEDIR,bind-try<br/>/var/lib/mysql/mysql.sock,bind-try<br/>/home/mysql/mysql.sock,bind-try<br/>/tmp/mysql.sock,bind-try<br/>/run/mysqld/mysqld.sock,bind-try<br/>/var/run/mysqld.sock,bind-try<br/>/run/user/$UID,bind-try<br/>$PASSWD<br/>$GROUP<br/>/etc/exim.jail/$USER.conf $HOMEDIR/.msmtprc,copy-try<br/>/etc/php.ini,ro-bind-try<br/>/etc/php-fpm.conf,ro-bind-try<br/>/etc/php-fpm.d,ro-bind-try<br/>/var/run,ro-bind-try<br/>/var/lib,ro-bind-try<br/>/etc/imunify360/user_config/,ro-bind-try<br/>/etc/sysconfig/imunify360,ro-bind-try<br/>/opt/plesk/php,ro-bind-try<br/>/opt/alt,bind-try<br/>/opt/cpanel,bind-try<br/>/opt/psa,bind-try<br/>/var/lib/php/sessions,bind-try </span>', '', 'Un chemin absolu ou un chemin relatif à $SERVER_ROOT.', '');

$_tipsdb['namespaceConfVhAdd'] = new DAttrHelp("Fichier de modele Namespace supplementaire", 'Chemin vers un fichier de configuration existant contenant une liste de repertoires a monter ainsi que les methodes utilisees pour les monter. Si &quot;Fichier de modèle Namespace&quot; est aussi defini au niveau Serveur, les deux fichiers seront utilises.', '', 'Un chemin pouvant être absolu, relatif à $SERVER_ROOT ou relatif à $VH_ROOT.', '');

