$_tipsdb['note'] = new DAttrHelp("Notes", 'Ajoutez des notes pour vous-même.', '', '', '');

$_tipsdb['ocspCACerts'] = new DAttrHelp("Certificats CA OCSP", 'Indique l’emplacement du fichier ou sont stockes les certificats d’autorite de certification (CA) OCSP. Ces certificats servent a verifier les reponses de l’OCSP responder (et a s’assurer que ces reponses ne sont pas usurpees ou compromises autrement). Ce fichier doit contenir toute la chaine de certificats. Si ce fichier ne contient pas le certificat racine, LSWS devrait pouvoir trouver le certificat racine dans le repertoire systeme sans que vous l’ajoutiez au fichier; mais si cette validation echoue, vous devriez essayer d’ajouter votre certificat racine a ce fichier.<br/><br/>Ce parametre est facultatif. S’il n’est pas defini, le serveur verifiera automatiquement &quot;Fichier de certificats CA&quot;.', '', 'Nom de fichier pouvant être un chemin absolu ou un chemin relatif à $SERVER_ROOT.', '');

$_tipsdb['ocspRespMaxAge'] = new DAttrHelp("Age maximal de reponse OCSP (s)", 'Cette option definit l’age maximal autorise pour une reponse OCSP. Si une reponse OCSP est plus ancienne que cet age maximal, le serveur contactera l’OCSP responder pour obtenir une nouvelle reponse. La valeur par defaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>86400</span>. L’age maximal peut etre desactive en definissant cette valeur sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>-1</span>.', '', 'Entier de secondes', '');

$_tipsdb['ocspResponder'] = new DAttrHelp("OCSP Responder", 'Indique l’URL de l’OCSP responder a utiliser. Si elle n’est pas definie, le serveur tentera de contacter l’OCSP responder detaille dans le certificat emetteur de l’autorite de certification. Certains certificats emetteurs peuvent ne pas indiquer d’URL d’OCSP responder.', '', 'URL commencant par <span class=&quot;lst-inline-token lst-inline-token--value&quot;>http://</span>', '<span class=&quot;lst-inline-token lst-inline-token--value&quot;>http://rapidssl-ocsp.geotrust.com </span>');

$_tipsdb['opsAuditRetainFiles'] = new DAttrHelp("Fichiers conservés du journal d'activité", 'Indique le nombre maximal de fichiers d&#039;audit d&#039;operations a conserver pour la console WebAdmin. Valeur par defaut si non definie: 30 fichiers.', 'Augmentez cette valeur si vous avez besoin d&#039;une piste d&#039;audit plus longue, mais gardez a l&#039;esprit que davantage de fichiers utiliseront plus d&#039;espace disque.', 'Nombre entier', '');

$_tipsdb['outBandwidth'] = new DAttrHelp("Bande passante sortante (octets/s)", 'Le débit sortant maximal autorisé vers une seule adresse IP, quel que soit le nombre de connexions établies. La bande passante réelle peut être légèrement supérieure à ce réglage pour des raisons d’efficacité. La bande passante est allouée par unités de 4KB. Définissez <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span> pour désactiver le throttling. Les limites de bande passante par client (octets/s) peuvent être définies au niveau serveur ou virtual host, où les réglages de niveau virtual host remplacent les réglages de niveau serveur.', ' Définissez la bande passante par unités de 8KB pour de meilleures performances.<br/><br/> Les IP ou sous-réseaux de confiance ne sont pas affectés.', 'Nombre entier', '');

$_tipsdb['pcKeepAliveTimeout'] = new DAttrHelp("Expiration keepalive de connexion", 'Indique la duree maximale en secondes pendant laquelle une connexion persistante inactive reste ouverte.<br/><br/>Avec la valeur &quot;-1&quot;, la connexion n&#039;expirera jamais. Avec 0 ou plus, la connexion sera fermee apres l&#039;ecoulement de cette duree en secondes.', '', 'Nombre entier', '');

$_tipsdb['perClientConnLimit'] = new DAttrHelp("Limitation par client", 'Ces reglages de controle de connexion sont bases sur l&#039;IP du client. Ils aident a attenuer les attaques DoS (Denial of Service) et DDoS (Distributed Denial of Service).', '', '', '');

$_tipsdb['persistConn'] = new DAttrHelp("Connexion persistante", 'Indique s&#039;il faut garder la connexion ouverte apres le traitement d&#039;une requete. Les connexions persistantes peuvent ameliorer les performances, mais certaines applications FastCGI externes ne les prennent pas totalement en charge. La valeur par defaut est &quot;On&quot;.', '', 'Sélectionner avec les boutons radio', '');

$_tipsdb['phpIniOverride'] = new DAttrHelp("Remplacement de php.ini", 'Utilisé pour remplacer les paramètres php.ini dans le contexte actuel (niveau hôte virtuel ou niveau contexte).<br/><br/>Les directives prises en charge sont:<br/>php_value<br/>php_flag<br/>php_admin_value<br/>php_admin_flag<br/><br/>Toutes les autres lignes/directives seront ignorées.', '', 'La syntaxe de remplacement est similaire à celle d’Apache: une liste de directives et de leurs valeurs séparées par des retours à la ligne, chaque directive étant précédée de php_value, php_flag, php_admin_value ou php_admin_flag selon le cas.', 'php_value include_path &quot;.:/usr/local/lib/php&quot;<br/>php_admin_flag engine on<br/>php_admin_value open_basedir &quot;/home&quot;');

$_tipsdb['pid'] = new DAttrHelp("PID", 'PID (ID de processus) du processus serveur actuel.', 'Le PID change à chaque redémarrage du serveur.', '', '');

$_tipsdb['procHardLimit'] = new DAttrHelp("Limite stricte de processus", 'Semblable à &quot;Limite souple de processus&quot;, sauf que la limite souple peut être relevée jusqu’à la limite stricte depuis un processus utilisateur. La limite stricte peut être définie au niveau serveur ou au niveau d’une application externe individuelle. La limite de niveau serveur sera utilisée si elle n’est pas définie au niveau de l’application individuelle. La valeur par défaut du système d’exploitation sera utilisée si la valeur est absente aux deux niveaux ou définie sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>.', '', 'Nombre entier', '');

$_tipsdb['procSoftLimit'] = new DAttrHelp("Limite souple de processus", 'Limite le nombre total de processus pouvant etre crees pour le compte d&#039;un utilisateur. Tous les processus existants seront comptes dans cette limite, pas seulement les nouveaux processus a demarrer.<br/><br/>La limite peut etre definie au niveau serveur ou au niveau d&#039;une application externe individuelle. La limite de niveau serveur sera utilisee si elle n&#039;est pas definie au niveau de l&#039;application. La valeur par defaut du systeme d&#039;exploitation sera utilisee si cette valeur est 0 ou absente aux deux niveaux.', 'Les scripts PHP peuvent demander la creation de processus. Le but principal de cette limite est de servir de derniere ligne de defense contre les fork bombs et autres attaques causees par des processus PHP creant d&#039;autres processus.<br/><br/>Une valeur trop basse peut nuire fortement au fonctionnement. Le reglage sera donc ignore sous certains niveaux.<br/><br/>Lorsque <b>Run On Start Up</b> est defini sur &quot;Yes (Daemon mode)&quot;, la limite reelle de processus sera superieure a ce reglage pour s&#039;assurer que les processus parents ne sont pas limites.', 'Nombre entier', '');

$_tipsdb['proxyContext'] = new DAttrHelp("Contexte proxy", 'Un contexte proxy permet a cet hote virtuel d&#039;agir comme serveur proxy inverse transparent. Ce serveur proxy peut etre place devant tout serveur web ou serveur d&#039;applications prenant en charge le protocole HTTP. Le serveur web externe pour lequel cet hote virtuel fait office de proxy doit etre defini dans &quot;Applications externes&quot; avant la configuration d&#039;un contexte proxy.', '', '', '');

$_tipsdb['proxyProtocol'] = new DAttrHelp("Protocole PROXY", 'Liste d’IP/sous-réseaux pour les proxies front-end qui communiquent avec ce serveur à l’aide du protocole PROXY. Une fois défini, le serveur utilisera le protocole PROXY pour les connexions entrantes depuis les IP/sous-réseaux listés, ou reviendra à une connexion normale si le protocole PROXY n’est pas disponible.<br/><br/>S’applique aux connexions HTTP, HTTPS, HTTP2 et websocket.', '', 'Liste d’adresses IP ou de sous-réseaux délimitée par des virgules.', '');

$_tipsdb['proxyWebServer'] = new DAttrHelp("Serveur web", 'Indique le nom du serveur web externe. Ce serveur web externe doit etre defini dans la section &quot;Applications externes&quot; au niveau serveur ou hote virtuel.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['quicBasePLPMTU'] = new DAttrHelp("Valeur de base PLPMTU", 'La valeur maximale de PLPMTU (taille maximale de paquet sans en-têtes), en octets, que QUIC utilisera par défaut. Définir ceci sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span> permettra à QUIC de choisir la taille.<br/><br/>Ce réglage doit être inférieur à &quot;Valeur max. PLPMTU&quot;.<br/><br/>Valeur par défaut: 0', '', '0 ou nombre entier entre 1200 et 65527', '');

$_tipsdb['quicCfcw'] = new DAttrHelp("Fenêtre de contrôle de flux de connexion", 'La taille initiale du tampon alloué pour une connexion QUIC. La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>1.5M</span>.', 'Une taille de fenêtre plus grande utilisera plus de mémoire.', 'Nombre entre 64K et 512M', '');

$_tipsdb['quicCongestionCtrl'] = new DAttrHelp("Contrôle de congestion", 'L’algorithme de contrôle de congestion utilisé. Il peut être défini manuellement ou laissé à la bibliothèque QUIC utilisée en sélectionnant l’option &quot;Default&quot;.<br/><br/>Valeur par défaut: Default', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['quicEnable'] = new DAttrHelp("Activer HTTP3/QUIC", 'Active le protocole réseau HTTP3/QUIC pour tout le serveur. La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>.', 'Lorsque ce réglage est défini sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>, HTTP3/QUIC peut toujours être désactivé au niveau listener via le réglage &quot;Ouvrir le port HTTP3/QUIC (UDP)&quot;, ou au niveau virtual host via le réglage &quot;Activer HTTP3/QUIC&quot;.', 'Sélectionner avec les boutons radio', '');

$_tipsdb['quicEnableDPLPMTUD'] = new DAttrHelp("Activer DPLPMTUD", 'Active Datagram Packetization Layer Path Maximum Transmission Unit Discovery (DPLPMTUD).<br/><br/><b>   <a href="     https://tools.ietf.org/html/rfc8899   " target="_blank" rel="noopener noreferrer">     Background on DPLPMTUD (RFC 8899)   </a> </b><br/><br/>Valeur par défaut: Yes', '', 'Sélectionner avec les boutons radio', '');

$_tipsdb['quicHandshakeTimeout'] = new DAttrHelp("Délai d'expiration de la poignée de main (secs)", 'Le temps en secondes accordé à une nouvelle connexion QUIC pour terminer son handshake, après quoi la connexion est abandonnée. La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>10</span>.', '', 'Nombre entier entre 1 et 15', '');

$_tipsdb['quicIdleTimeout'] = new DAttrHelp("Délai d'expiration d'inactivité (secs)", 'Le temps en secondes après lequel une connexion QUIC inactive sera fermée. La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>30</span>.', '', 'Nombre entier entre 10 et 30', '');

$_tipsdb['quicMaxCfcw'] = new DAttrHelp("Fenêtre max. de contrôle de flux de connexion", 'Spécifie la taille maximale qu’un tampon de fenêtre de contrôle de flux de connexion est autorisé à atteindre à cause de l’auto-tuning de fenêtre.<br/><br/>La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>, ce qui signifie que la valeur de &quot;Fenêtre de contrôle de flux de connexion&quot; est utilisée et qu’aucun auto-tuning n’est effectué.', 'Une taille de fenêtre plus grande utilisera plus de mémoire.', '0 ou un nombre entre 64K et 512M', '');

$_tipsdb['quicMaxPLPMTU'] = new DAttrHelp("Valeur max. PLPMTU", 'La limite supérieure de sondage PLPMTU (taille maximale de paquet sans en-têtes), en octets. Ce réglage est utilisé pour limiter la &quot;taille maximale de paquet&quot; dans l’espace de recherche DPLPMTUD. Définir ceci sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span> permettra à QUIC de choisir la taille (par défaut, LSQUIC suppose que le MTU est de 1,500 octets (Ethernet)).<br/><br/>Ce réglage doit être supérieur à &quot;Valeur de base PLPMTU&quot;.<br/>Valeur par défaut: 0', '', '0 ou nombre entier entre 1200 et 65527', '');

$_tipsdb['quicMaxSfcw'] = new DAttrHelp("Fenêtre max. de contrôle de flux de stream", 'Spécifie la taille maximale qu’une fenêtre de contrôle de flux de stream est autorisée à atteindre à cause de l’auto-tuning de fenêtre.<br/><br/>La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>, ce qui signifie que la valeur de &quot;Fenêtre de contrôle de flux de stream&quot; est utilisée et qu’aucun auto-tuning n’est effectué.', 'Une taille de fenêtre plus grande utilisera plus de mémoire.', '0 ou un nombre entre 64K et 128M', '');

$_tipsdb['quicMaxStreams'] = new DAttrHelp("Streams simultanés max. par connexion", 'Le nombre maximal de streams simultanés autorisés par connexion QUIC. La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>100</span>.', '', 'Nombre entier entre 10 et 1000', '');

$_tipsdb['quicSfcw'] = new DAttrHelp("Fenêtre de contrôle de flux de stream", 'La quantité initiale de données qu’une connexion QUIC accepte de recevoir par stream. La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>1M</span>.', 'Une taille de fenêtre plus grande utilisera plus de mémoire.', 'Nombre entre 64K et 128M', '');

$_tipsdb['quicShmDir'] = new DAttrHelp("Répertoire SHM QUIC", 'Spécifie le répertoire utilisé pour enregistrer les données QUIC dans la mémoire partagée.<br/><br/>Par défaut, le répertoire SHM par défaut du serveur, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/dev/shm</span>, sera utilisé.', 'Une partition basée sur la RAM, telle que <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/dev/shm</span>, est recommandée.', 'Chemin', '');

$_tipsdb['quicVersions'] = new DAttrHelp("Versions HTTP3/QUIC", 'Liste des versions HTTP3/QUIC activées. Ce réglage ne doit être utilisé que pour limiter la prise en charge HTTP3/QUIC aux versions listées, et il est préférable de le laisser vide.', 'Il est recommandé de laisser ce réglage vide afin que la meilleure configuration soit appliquée automatiquement.', 'Liste séparée par des virgules', 'h3-29, h3-Q050');

$_tipsdb['railsDefaults'] = new DAttrHelp("Paramètres par défaut Rack/Rails", 'Configurations par defaut pour les applications Rack/Rails. Ces reglages peuvent etre remplaces au niveau du contexte.', '', '', '');

$_tipsdb['rcvBufSize'] = new DAttrHelp("Taille du tampon de réception (octets)", 'La taille du tampon de réception de chaque socket TCP. <span class=&quot;lst-inline-token lst-inline-token--value&quot;>512K</span> est la taille maximale autorisée du tampon.', ' Il est recommandé de laisser cette valeur sur &quot;Not Set&quot; ou de la définir sur 0 pour utiliser la taille de tampon par défaut du système d’exploitation.<br/> Un grand tampon de réception augmentera les performances lors du traitement de requêtes entrantes avec de grandes charges utiles, par exemple les téléversements de fichiers.<br/> Définir ceci sur une valeur plus basse réduira le débit et l’utilisation mémoire par socket, permettant au serveur d’avoir plus de sockets simultanés lorsque la mémoire est un goulot d’étranglement.', 'Nombre entier', '');

$_tipsdb['realm'] = new DAttrHelp("Realm", 'Indique le realm d’autorisation pour ce contexte. Lorsqu’il est indique, un nom d’utilisateur et un mot de passe valides doivent etre fournis pour acceder a ce contexte. &quot;Realms d&#039;autorisation&quot; sont configures dans la section &quot;Hôte virtuel - Sécurité&quot;. Ce parametre utilise le &quot;Nom du realm&quot; de chaque realm.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['realmName'] = new DAttrHelp("Nom du realm", 'Indique un nom unique pour le realm d’autorisation.', '', '', '');

$_tipsdb['realms'] = new DAttrHelp("Realms d'autorisation", 'Liste tous les realms d&#039;autorisation pour ce virtual host. Les realms d&#039;autorisation servent a empecher les utilisateurs non autorises d&#039;acceder aux pages web protegees. Un realm est un repertoire d&#039;utilisateurs contenant des noms d&#039;utilisateur et des mots de passe, avec des classifications de groupe facultatives. L&#039;autorisation est effectuee au niveau du contexte. Comme differents contextes peuvent partager le meme realm (base de donnees utilisateur), les realms sont definis separement des contextes qui les utilisent. Vous pouvez faire reference a un realm par ces noms dans la configuration du contexte.', '', '', '');

$_tipsdb['realtimerpt'] = new DAttrHelp("Statistiques en temps réel", 'Le lien Real-Time Statistics mène à une page contenant un rapport d&#039;état du serveur en temps réel. C&#039;est un outil pratique pour surveiller le système.<br/><br/>Le rapport affiche un instantané des statistiques de votre serveur. La fréquence d&#039;actualisation de cet instantané est contrôlée par la liste déroulante Refresh Interval dans l&#039;angle supérieur droit.<br/><br/>Le rapport contient les sections suivantes: <ul><li>Server Health affiche les statistiques de base du serveur, la durée de fonctionnement, la charge et les IP bloquées par Anti-DDoS.</li>   <li>Server liste les statistiques actuelles de débit du trafic, de connexions et de requêtes.</li>  <li>Virtual Host affiche les états de traitement des requêtes et les états des applications externes pour chaque hôte virtuel.</li>  <li>External Application liste les applications externes en cours d&#039;exécution et leurs statistiques d&#039;utilisation. Le processus démon CGI lscgid fonctionne toujours comme une application externe.</li> </ul><br/><br/>De nombreuses lignes de Real-Time Statistics comportent une icône de graphique. Cliquer sur cette icône ouvre un graphique des statistiques de cette ligne mis à jour en temps réel.<br/><br/>Dans la section Server, à côté de Requests, un lien intitulé (Details) apparaît. Ce lien mène à Requests Snapshot, où vous pouvez voir des informations détaillées sur les clients qui effectuent certains types de requêtes ou sur les aspects du site qui créent des goulots d&#039;étranglement. Les champs de la zone bleue permettent de filtrer l&#039;instantané afin d&#039;isoler certaines parties du serveur ou de rechercher des clients effectuant certaines actions.', '', '', '');

$_tipsdb['recaptchaAllowedRobotHits'] = new DAttrHelp("Hits de robots autorisés", 'Nombre de hits par 10 secondes autorisés pour laisser passer les ‘good bots’. Les bots seront toujours limités lorsque le serveur est sous charge.<br/><br/>La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>3</span>.', '', 'Nombre entier', '');

$_tipsdb['recaptchaBotWhiteList'] = new DAttrHelp("Liste blanche de bots", 'Liste d’user agents personnalisés à autoriser. Ils seront soumis aux limitations des ‘good bots’, y compris allowedRobotHits.', '', 'Liste d’user agents, un par ligne. Regex est pris en charge.', '');

$_tipsdb['recaptchaMaxTries'] = new DAttrHelp("Nombre max. d’essais", 'Max Tries spécifie le nombre maximal de tentatives CAPTCHA autorisées avant de refuser le visiteur.<br/><br/>La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>3</span>.', '', 'Nombre entier', '');

$_tipsdb['recaptchaRegConnLimit'] = new DAttrHelp("Limite de connexions", 'Le nombre de connexions simultanées (SSL et non SSL) nécessaires pour activer CAPTCHA. CAPTCHA continuera d’être utilisé jusqu’à ce que le nombre de connexions simultanées tombe sous ce nombre.<br/><br/>La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>15000</span>.', '', 'Nombre entier', '');

$_tipsdb['recaptchaSecretKey'] = new DAttrHelp("Clé secrète", 'La clé privée attribuée par les services reCAPTCHA ou hCaptcha.<br/><br/>Avec reCAPTCHA, une clé secrète par défaut sera utilisée si aucune n’est définie (non recommandé).', '', '', '');

$_tipsdb['recaptchaSiteKey'] = new DAttrHelp("Clé de site", 'La clé publique attribuée par les services reCAPTCHA ou hCaptcha.<br/><br/>Avec reCAPTCHA, une clé de site par défaut sera utilisée si aucune n’est définie (non recommandé).', '', '', '');

$_tipsdb['recaptchaSslConnLimit'] = new DAttrHelp("Limite de connexions SSL", 'Le nombre de connexions SSL simultanées nécessaires pour activer CAPTCHA. CAPTCHA continuera d’être utilisé jusqu’à ce que le nombre de connexions simultanées tombe sous ce nombre.<br/><br/>La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>10000</span>.', '', 'Nombre entier', '');

$_tipsdb['recaptchaType'] = new DAttrHelp("Type de CAPTCHA", 'Spécifiez le type de CAPTCHA à utiliser avec les paires de clés.<br/>Si aucune paire de clés n’a été fournie et que ce réglage est défini sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Not Set</span>, une paire de clés par défaut de type CAPTCHA <span class=&quot;lst-inline-token lst-inline-token--value&quot;>reCAPTCHA Invisible</span> sera utilisée.<br/><br/><span class=&quot;lst-inline-token lst-inline-token--value&quot;>reCAPTCHA Checkbox</span> affichera un CAPTCHA à case à cocher que le visiteur devra valider. (nécessite &quot;Clé de site&quot;, &quot;Clé secrète&quot;)<br/><br/><span class=&quot;lst-inline-token lst-inline-token--value&quot;>reCAPTCHA Invisible</span> tentera de valider le CAPTCHA automatiquement et, en cas de succès, redirigera vers la page souhaitée. (nécessite &quot;Clé de site&quot;, &quot;Clé secrète&quot;)<br/><br/><span class=&quot;lst-inline-token lst-inline-token--value&quot;>hCaptcha</span> peut être utilisé pour prendre en charge le fournisseur CAPTCHA <a href="https://www.hcaptcha.com" target="_blank" rel="noopener noreferrer">hCaptcha</a>. (nécessite &quot;Clé de site&quot;, &quot;Clé secrète&quot;)<br/><br/>La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>reCAPTCHA Invisible</span>.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['recaptchaVhReqLimit'] = new DAttrHelp("Limite de requetes concurrentes", 'Nombre de requetes concurrentes necessaire pour activer CAPTCHA. CAPTCHA continuera d&#039;etre utilise jusqu&#039;a ce que le nombre de requetes concurrentes tombe sous cette valeur.<br/><br/>La valeur par defaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>15000</span>.', '', 'Nombre entier', '');

$_tipsdb['redirectContext'] = new DAttrHelp("Contexte de redirection", 'Un contexte de redirection peut servir a transferer une URI ou un groupe d&#039;URI vers un autre emplacement. L&#039;URI de destination peut se trouver sur le meme site web (redirection interne) ou etre une URI absolue pointant vers un autre site web (redirection externe).', '', '', '');

$_tipsdb['renegProtection'] = new DAttrHelp("Protection contre la renegociation SSL", 'Indique s’il faut activer la protection contre la renegociation SSL pour se defendre contre les attaques basees sur le handshake SSL. La valeur par defaut est &quot;Yes&quot;.', 'Ce parametre peut etre active aux niveaux listener et hote virtuel.', 'Sélectionner avec les boutons radio', '');

$_tipsdb['required'] = new DAttrHelp("Require (utilisateurs/groupes autorises)", 'Indique quels utilisateurs/groupes peuvent acceder a ce contexte. Cela permet d’utiliser une base de donnees utilisateur/groupe (indiquee dans &quot;Realm&quot;) sur plusieurs contextes, tout en n’autorisant que certains utilisateurs/groupes de cette base pour ce contexte.', '', 'La syntaxe est compatible avec la directive Require d’Apache. Par exemple: <ul> <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>user username [username ...]</span><br/>Seuls les utilisateurs listes peuvent acceder a ce contexte.</li> <li> <span class=&quot;lst-inline-token lst-inline-token--value&quot;>group groupid [groupid ...]</span><br/>Seuls les utilisateurs appartenant aux groupes listes peuvent acceder a ce contexte.</li> </ul> Si ce parametre n’est pas indique, tous les utilisateurs valides pourront acceder a cette ressource.', '');

$_tipsdb['requiredPermissionMask'] = new DAttrHelp("Masque de permissions requis", 'Spécifie le masque de permissions requis pour les fichiers statiques que le serveur servira. Par exemple, si seuls les fichiers lisibles par tout le monde doivent être servis, définissez la valeur sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0004</span>. Voir <span class=&quot;lst-inline-token lst-inline-token--command&quot;>man 2 stat</span> pour toutes les valeurs.', '', 'nombres octaux', '');

$_tipsdb['respBuffer'] = new DAttrHelp("Mise en tampon des reponses", 'Indique s&#039;il faut mettre en tampon les reponses recues des applications externes. Si un script &quot;nph-&quot; (Non-Parsed-Header) est detecte, la mise en tampon est desactivee pour les reponses contenant des en-tetes HTTP complets.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['restart'] = new DAttrHelp("Appliquer les changements/Graceful Restart", 'En cliquant sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Graceful Restart</span>, un nouveau processus serveur est lancé. Pour <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Graceful Restart</span>, l&#039;ancien processus serveur ne se termine qu&#039;après la fin de toutes les requêtes qui lui sont adressées (ou lorsque la limite &quot;Timeout de redemarrage graceful (s)&quot; est atteinte).<br/><br/>Les modifications de configuration sont appliquées au prochain redémarrage. <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Graceful Restart</span> applique ces modifications sans interruption du serveur.', 'Graceful restart prend moins de 2 secondes pour générer un nouveau processus serveur.', '', '');

$_tipsdb['restrained'] = new DAttrHelp("Restreint", 'Indique si les fichiers situes au-dela de la racine de cet hote virtuel ($VH_ROOT) peuvent etre accessibles via ce site web. Si la valeur est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>, seuls les fichiers sous $VH_ROOT seront accessibles et l&#039;acces aux liens symboliques ou aux contextes pointant vers des fichiers ou repertoires situes au-dela de $VH_ROOT sera refuse. Cela ne limite toutefois pas l&#039;accessibilite des scripts CGI. C&#039;est utile dans les environnements d&#039;hebergement partage. &quot;Suivre les liens symboliques&quot; peut etre defini sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span> pour permettre aux utilisateurs d&#039;utiliser des liens symboliques sous $VH_ROOT, mais rien au-dela de $VH_ROOT.', ' Activez-le dans l&#039;environnement d&#039;hebergement partage.', 'Sélectionner avec les boutons radio', '');

$_tipsdb['restrictedDirPermissionMask'] = new DAttrHelp("Masque de permissions restreint pour répertoires de scripts", 'Spécifie le masque de permissions restreint des répertoires parents des fichiers de script que le serveur ne servira pas. Par exemple, pour interdire le service de scripts PHP dans un répertoire accessible en écriture au groupe et à tout le monde, définissez le masque sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>022</span>. La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>000</span>. Cette option peut être utilisée pour empêcher le service de scripts sous un répertoire de fichiers téléversés.<br/><br/>Voir <span class=&quot;lst-inline-token lst-inline-token--command&quot;>man 2 stat</span> pour toutes les valeurs.', '', 'nombres octaux', '');

$_tipsdb['restrictedPermissionMask'] = new DAttrHelp("Masque de permissions restreint", 'Spécifie le masque de permissions restreint pour les fichiers statiques que le serveur ne servira pas. Par exemple, pour interdire le service des fichiers exécutables, définissez le masque sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0111</span>.<br/><br/>Voir <span class=&quot;lst-inline-token lst-inline-token--command&quot;>man 2 stat</span> pour toutes les valeurs.', '', 'nombres octaux', '');

$_tipsdb['restrictedScriptPermissionMask'] = new DAttrHelp("Masque de permissions restreint pour scripts", 'Spécifie le masque de permissions restreint pour les fichiers de script que le serveur ne servira pas. Par exemple, pour interdire le service des scripts PHP accessibles en écriture au groupe et à tout le monde, définissez le masque sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>022</span>. La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>000</span>.<br/><br/>Voir <span class=&quot;lst-inline-token lst-inline-token--command&quot;>man 2 stat</span> pour toutes les valeurs.', '', 'nombres octaux', '');

$_tipsdb['retryTimeout'] = new DAttrHelp("Delai de nouvelle tentative (s)", 'Indique la periode pendant laquelle le serveur attend avant de reessayer une application externe ayant rencontre un probleme de communication auparavant.', '', 'Nombre entier', '');

$_tipsdb['reusePort'] = new DAttrHelp("Activer REUSEPORT", 'Utilise l&#039;option de socket SO_REUSEPORT pour distribuer le trafic entrant a plusieurs workers. Ce reglage n&#039;est effectif que pour les licences multi-worker. Lorsqu&#039;il est active, tous les workers sont automatiquement lies a ce listener et la configuration &quot;Liaison&quot; est ignoree.<br/><br/>Valeur par defaut: active', '', 'Sélectionner avec les boutons radio', '');

$_tipsdb['rewriteBase'] = new DAttrHelp("Base rewrite", 'Indique l’URL de base pour les regles rewrite.', '', 'URL', '');

$_tipsdb['rewriteInherit'] = new DAttrHelp("Heriter rewrite", 'Indique s’il faut heriter les regles rewrite des contextes parents. Si rewrite est active et non herite, la base rewrite et les regles rewrite definies dans ce contexte seront utilisees.', '', 'Sélectionner avec les boutons radio', '');

$_tipsdb['rewriteLogLevel'] = new DAttrHelp("Niveau de journalisation", 'Indique le niveau de détail de la sortie de débogage du moteur de réécriture. Cette valeur va de <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span> à <span class=&quot;lst-inline-token lst-inline-token--value&quot;>9</span>. <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span> désactive la journalisation. <span class=&quot;lst-inline-token lst-inline-token--value&quot;>9</span> produit le journal le plus détaillé. Le journal d’erreurs du serveur et de l’hôte virtuel &quot;Niveau de journalisation&quot; doit être défini au moins sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>INFO</span> pour que cette option prenne effet. C’est utile lors du test de règles de réécriture.', '', 'Nombre entier', '');

$_tipsdb['rewriteMapLocation'] = new DAttrHelp("Emplacement", 'Indique l’emplacement de la rewrite map avec la syntaxe <span class=&quot;lst-inline-token lst-inline-token--value&quot;>MapType:MapSource</span>.<br/>Le moteur de réécriture LiteSpeed prend en charge trois types de rewrite maps: <ul> 	<li><b>Texte brut standard</b> <blockquote> 		<b>MapType:</b> txt;<br/>		<b>MapSource:</b> chemin de fichier vers un fichier ASCII brut valide. </blockquote> 		Chaque ligne de ce fichier doit contenir deux éléments séparés par des espaces. Le premier élément est la clé et le second est la valeur. Des commentaires peuvent être ajoutés avec le signe initial &quot;<span class=&quot;lst-inline-token lst-inline-token--value&quot;>#</span>&quot;. 	</li> 	<li><b>Texte brut aléatoire</b> <blockquote> 		<b>MapType:</b> rnd;<br/>		<b>MapSource:</b> chemin de fichier d’un fichier ASCII brut valide. </blockquote> 		Le format du fichier est similaire à celui du fichier texte brut standard, sauf que le second élément peut contenir plusieurs choix séparés par le signe &quot;<span class=&quot;lst-inline-token lst-inline-token--value&quot;>|</span>&quot; et sélectionnés aléatoirement par le moteur de réécriture. 	</li> 	<li><b>Fonction interne</b> <blockquote> 	    <b>MapType:</b> int;<br/>		<b>MapSource:</b> fonction de chaîne interne </blockquote> 		4 fonctions sont disponibles: 		<ul> 			<li><b>toupper:</b> convertit la clé de recherche en majuscules.</li> 			<li><b>tolower:</b> convertit la clé de recherche en minuscules.</li> 			<li><b>escape:</b> applique l’encodage URL à la clé de recherche.</li> 			<li><b>unescape:</b> applique le décodage URL à la clé de recherche.</li> 		</ul> 	</li> 	Les types de map suivants disponibles dans Apache ne sont pas implémentés dans LiteSpeed:<br/>Hash File et External Rewriting Program. </ul> L’implémentation du moteur de réécriture LiteSpeed suit les spécifications du moteur de réécriture Apache. Pour plus de détails sur rewrite map, consultez la <a href="http://httpd.apache.org/docs/current/mod/mod_rewrite.html" target="_blank" rel="noopener noreferrer">documentation mod_rewrite d’Apache</a>.', '', 'Chaîne', '');

$_tipsdb['rewriteMapName'] = new DAttrHelp("Nom", 'Indique un nom unique pour la rewrite map au niveau hôte virtuel. Ce nom sera utilisé par une référence de mappage dans les règles de réécriture. Pour référencer ce nom, utilisez l’une des syntaxes suivantes: <blockquote><code> $\{MapName:LookupKey\}<br/>$\{MapName:LookupKey|DefaultValue\} </code></blockquote><br/>L’implémentation du moteur de réécriture LiteSpeed suit les spécifications du moteur de réécriture Apache. Pour plus de détails sur les rewrite maps, consultez la <a href="http://httpd.apache.org/docs/current/mod/mod_rewrite.html" target="_blank" rel="noopener noreferrer">documentation mod_rewrite d’Apache</a>.', '', 'chaîne', '');

$_tipsdb['rewriteRules'] = new DAttrHelp("Règles de réécriture", 'Indique une liste de règles de réécriture au niveau hôte virtuel.<br/><br/>N’ajoutez PAS ici de règles de réécriture au niveau racine des documents. Si vous avez des règles de réécriture au niveau racine des documents provenant de .htaccess, vous devez plutôt créer un contexte statique avec uri &quot;/&quot; et y ajouter les règles de réécriture.<br/><br/>Une règle de réécriture comprend une directive <span class=&quot;lst-inline-token lst-inline-token--value&quot;>RewriteRule</span> et peut être précédée, facultativement, de plusieurs directives <span class=&quot;lst-inline-token lst-inline-token--value&quot;>RewriteCond</span>. <ul>   <li>Chaque directive doit tenir sur une seule ligne.</li>   <li>     <span class=&quot;lst-inline-token lst-inline-token--value&quot;>RewriteCond</span> et <span class=&quot;lst-inline-token lst-inline-token--value&quot;>RewriteRule</span> suivent la syntaxe des directives rewrite d’Apache. Copiez-collez simplement les directives rewrite depuis vos fichiers de configuration Apache.   </li>   <li>     Il existe de légères différences entre les implémentations LiteSpeed et Apache mod_rewrite:     <ul>       <li>         <span class=&quot;lst-inline-token lst-inline-token--value&quot;>%\{LA-U:variable\}</span> et <span class=&quot;lst-inline-token lst-inline-token--value&quot;>%\{LA-F:variable\}</span> sont ignorées par le moteur de réécriture LiteSpeed       </li>       <li>         Deux nouvelles variables serveur sont ajoutées dans le moteur de réécriture LiteSpeed: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>%\{CURRENT_URI\}</span> représente l’URI actuelle traitée par le moteur de réécriture, et <span class=&quot;lst-inline-token lst-inline-token--value&quot;>%\{SCRIPT_NAME\}</span> a la même signification que la variable d’environnement CGI correspondante.       </li>       <li>         Le moteur de réécriture LiteSpeed arrête de traiter les règles de réécriture après avoir rencontré un indicateur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>[L]</span> afin d’éviter les boucles, tandis qu’Apache mod_rewrite n’arrête le traitement des règles de réécriture que pour l’itération actuelle. Ce comportement est similaire à celui de l’indicateur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>[END]</span> dans Apache mod_rewrite.       </li>     </ul>   </li> </ul><br/>L’implémentation du moteur de réécriture LiteSpeed suit les spécifications du moteur de réécriture Apache. Pour plus de détails sur les règles de réécriture, consultez la <a href="https://httpd.apache.org/docs/current/mod/mod_rewrite.html" target="_blank" rel="noopener noreferrer">   documentation mod_rewrite d’Apache </a> et le <a href="https://httpd.apache.org/docs/current/rewrite/" target="_blank" rel="noopener noreferrer">   guide Apache de réécriture d’URL </a>.', '', 'chaîne', '');

$_tipsdb['rubyBin'] = new DAttrHelp("Chemin Ruby", 'Chemin vers l&#039;exécutable Ruby. Généralement, il s&#039;agit de /usr/bin/ruby ou /usr/local/bin/ruby selon l&#039;emplacement d&#039;installation de Ruby.', '', 'Chemin absolu', '');

$_tipsdb['runOnStartUp'] = new DAttrHelp("Executer au demarrage", 'Indique s&#039;il faut demarrer l&#039;application externe au demarrage du serveur. Applicable uniquement aux applications externes qui peuvent gerer leurs propres processus enfants et dont la valeur &quot;Instances&quot; est definie sur &quot;1&quot;.<br/><br/>Si active, les processus externes seront crees au demarrage du serveur plutot qu&#039;a l&#039;execution.<br/><br/>Lorsque &quot;Yes (Detached mode)&quot; est selectionne, tous les processus detaches peuvent etre redemarres au niveau serveur ou virtual host en touchant le fichier &#039;.lsphp_restart.txt&#039; sous $SERVER_ROOT/admin/tmp/ ou le repertoire $VH_ROOT/ respectivement.<br/><br/>Valeur par defaut: Yes (Detached mode)', ' Si le processus externe configure a une surcharge de demarrage importante, comme une app Rails, cette option doit etre activee pour reduire le temps de reponse de la premiere page.', 'Sélectionner avec les boutons radio', '');

$_tipsdb['runningAs'] = new DAttrHelp("Execute en tant que", 'Indique l’utilisateur/groupe sous lequel le processus serveur s’execute. Cela est defini avec les parametres &quot;--with-user&quot; et &quot;--with-group&quot; lors de l’execution de la commande configure avant l’installation. Pour reinitialiser ces valeurs, vous devez relancer configure et reinstaller.', ' Le serveur ne doit pas s’executer avec un utilisateur privilegie tel que &quot;root&quot;. Il est essentiel que le serveur soit configure pour s’executer avec une combinaison utilisateur/groupe non privilegiee sans acces login/shell. Un utilisateur/groupe <span class=&quot;lst-inline-token lst-inline-token--value&quot;>nobody</span> est generalement un bon choix.', '', '');

$_tipsdb['scgiContext'] = new DAttrHelp("Contexte SCGI", 'Les applications SCGI ne peuvent pas etre utilisees directement. Une application SCGI doit etre configuree comme gestionnaire de scripts ou associee a une URL au moyen d&#039;un contexte SCGI. Un contexte SCGI associe une URI a une application SCGI.', '', '', '');

$_tipsdb['scgiapp'] = new DAttrHelp("Application SCGI", 'Indique le nom de l’application SCGI. Cette application doit etre definie dans la section &quot;Applications externes&quot; au niveau serveur ou hote virtuel.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['servAction'] = new DAttrHelp("Actions", 'Cinq actions sont disponibles dans ce menu: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Graceful Restart</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Toggle Debug Logging</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Server Log Viewer</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Real-Time Statistics</span> et <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Compile PHP</span>. <ul><li>&quot;Appliquer les changements/Graceful Restart&quot; redémarre le processus serveur de manière graceful sans interrompre les requêtes en cours.</li> 	<li>&quot;Basculer la journalisation de débogage&quot; active ou désactive la journalisation de débogage.</li> 	<li>&quot;Visualiseur du journal du serveur&quot; permet d&#039;afficher le journal du serveur avec le visualiseur de journaux.</li> 	<li>&quot;Statistiques en temps réel&quot; permet d&#039;afficher l&#039;état du serveur en temps réel.</li> 	<li>Compile PHP permet de compiler PHP pour LiteSpeed Web Server.</li> </ul>', 'L&#039;utilitaire shell <span class=&quot;lst-inline-token lst-inline-token--command&quot;>$SERVER_ROOT/bin/lswsctrl</span> peut également être utilisé pour contrôler les processus du serveur, mais il nécessite un shell de connexion.', '', '');

$_tipsdb['servModules'] = new DAttrHelp("Modules serveur", 'La configuration des modules du serveur definit globalement les donnees de configuration des modules. Une fois definis, les listeners et les hotes virtuels ont acces aux modules et a leurs configurations.<br/><br/>Tous les modules a traiter doivent etre enregistres dans la configuration du serveur. La configuration du serveur definit egalement les valeurs par defaut des donnees de parametres de module. Ces valeurs peuvent etre heritees ou remplacees par les donnees de configuration du listener et de l&#039;hote virtuel.<br/><br/>La priorite d&#039;un module est definie uniquement au niveau serveur et heritee par les configurations de listener et d&#039;hote virtuel.', '', '', '');

$_tipsdb['serverName'] = new DAttrHelp("Nom du serveur", 'Nom unique pour ce serveur. S’il est vide, le hostname du serveur sera utilise par defaut.', '', '', '');

$_tipsdb['serverPriority'] = new DAttrHelp("Priorite", 'Indique la priorite des processus serveur. La valeur va de <span class=&quot;lst-inline-token lst-inline-token--value&quot;>-20</span> a <span class=&quot;lst-inline-token lst-inline-token--value&quot;>20</span>. Un nombre plus faible signifie une priorite plus elevee.', ' En general, une priorite plus elevee offre des performances web legerement meilleures sur un serveur charge. Ne definissez pas une priorite superieure a celle des processus de base de donnees.', 'Nombre entier', '');

$_tipsdb['servletContext'] = new DAttrHelp("Contexte Servlet", 'Les servlets peuvent etre importes individuellement au moyen de contextes de servlet. Un contexte de servlet indique simplement l&#039;URI du servlet et le nom du moteur de servlets. Utilisez-le uniquement si vous ne voulez pas importer toute l&#039;application web ou si vous voulez proteger differents servlets avec differents realms d&#039;autorisation. Cette URI a les memes exigences que pour un &quot;Contexte d&#039;application web Java&quot;.', '', '', '');

$_tipsdb['servletEngine'] = new DAttrHelp("Moteur Servlet", 'Indique le nom du moteur servlet qui sert cette application web. Les moteurs servlet doivent etre definis dans la section &quot;Applications externes&quot; au niveau serveur ou hote virtuel.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['setUidMode'] = new DAttrHelp("Mode Set UID de l’app externe", 'Indique comment l&#039;ID utilisateur est defini pour un processus d&#039;application externe. Trois choix sont disponibles: <ul><li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Server UID</span>: definit l&#039;ID utilisateur/groupe des processus d&#039;application externe sur le meme ID utilisateur/groupe que celui du serveur.</li>     <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>CGI File UID</span>: definit l&#039;ID utilisateur/groupe des processus CGI externes selon l&#039;ID utilisateur/groupe de l&#039;executable. Cette option s&#039;applique uniquement a CGI, pas a FastCGI ni LSPHP.</li>     <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Doc Root UID</span>: definit l&#039;ID utilisateur/groupe des processus d&#039;application externe selon l&#039;ID utilisateur/groupe de la racine des documents de l&#039;hote virtuel actuel.</li> </ul><br/><br/>Valeur par defaut: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Server UID</span>', ' Dans un environnement d&#039;hebergement partage, il est recommande d&#039;utiliser les modes <span class=&quot;lst-inline-token lst-inline-token--value&quot;>CGI File UID</span> ou <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Doc Root UID</span> afin d&#039;empecher les fichiers appartenant a un hote virtuel d&#039;etre accessibles par les scripts d&#039;application externe d&#039;un autre hote virtuel.', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['shHandlerName'] = new DAttrHelp("Nom du gestionnaire", 'Spécifie le nom de l&#039;application externe qui traite les fichiers de script lorsque le type de gestionnaire est LSAPI app, Web Server (Proxy), Fast CGI, SCGI, Load balancer, Servlet Engine ou uWSGI.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['shType'] = new DAttrHelp("Type de gestionnaire", 'Spécifie le type d&#039;application externe qui traite ces fichiers de script. Les types disponibles sont: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>LSAPI app</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Web Server (Proxy)</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Fast CGI</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>SCGI</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>CGI</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Load balancer</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Servlet Engine</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>uWSGI</span> ou <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Module Handler</span>. Sauf pour les types de gestionnaire <span class=&quot;lst-inline-token lst-inline-token--value&quot;>CGI</span> et <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Module Handler</span>, &quot;Nom du gestionnaire&quot; doit également être défini sur une application externe précédemment définie dans la section &quot;Applications externes&quot;.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['shmDefaultDir'] = new DAttrHelp("Répertoire SHM par défaut", 'Change le répertoire par défaut de la mémoire partagée vers le chemin spécifié. Si le répertoire n’existe pas, il sera créé. Toutes les données SHM seront stockées dans ce répertoire sauf indication contraire.', '', 'chemin', '');

$_tipsdb['showVersionNumber'] = new DAttrHelp("Signature du serveur", 'Indique s’il faut afficher la signature du serveur et le numero de version dans la valeur &quot;Server&quot; de l’en-tete de reponse. Il y a trois options: avec <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Hide Version</span>, seul <span class=&quot;lst-inline-token lst-inline-token--value&quot;>LiteSpeed</span> est affiche. Avec <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Show Version</span>, LiteSpeed et le numero de version sont affiches.  Avec <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Hide Full Header</span>, l’en-tete Server complet ne sera pas affiche dans l’en-tete de reponse.', ' Definissez sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Hide Version</span> si vous ne voulez pas exposer le numero de version du serveur.', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['sname'] = new DAttrHelp("Nom - Serveur", 'Nom unique qui identifie ce serveur. Il s&#039;agit du &quot;Nom du serveur&quot; spécifié dans la configuration générale.', '', '', '');

$_tipsdb['sndBufSize'] = new DAttrHelp("Taille du tampon d’envoi (octets)", 'La taille du tampon d’envoi de chaque socket TCP. <span class=&quot;lst-inline-token lst-inline-token--value&quot;>512K</span> est la taille maximale autorisée du tampon.', ' Il est recommandé de laisser cette valeur sur &quot;Not Set&quot; ou de la définir sur 0 pour utiliser la taille de tampon par défaut du système d’exploitation.<br/> Si votre site web sert de gros fichiers statiques, augmentez la taille du tampon d’envoi pour améliorer les performances.<br/> Définir ceci sur une valeur plus basse réduira le débit et l’utilisation mémoire par socket, permettant au serveur d’avoir plus de sockets simultanés lorsque la mémoire est un goulot d’étranglement.', 'Nombre entier', '');

$_tipsdb['softLimit'] = new DAttrHelp("Limite souple de connexions", 'Spécifie la limite souple de connexions simultanées autorisées depuis une IP. Cette limite souple peut être dépassée temporairement pendant &quot;Période de grâce (secs)&quot; tant que le nombre reste inférieur à &quot;Limite stricte de connexions&quot;, mais les connexions Keep-Alive seront fermées dès que possible jusqu’à ce que le nombre de connexions soit inférieur à la limite. Si le nombre de connexions reste au-dessus de la limite après &quot;Période de grâce (secs)&quot;, cette IP sera bloquée pendant &quot;Période de blocage (secs)&quot;.<br/><br/>Par exemple, si une page contient de nombreux petits graphiques, le navigateur peut essayer d’établir de nombreuses connexions en même temps, surtout avec les clients HTTP/1.0. Il faut permettre ces connexions pendant une courte période.<br/><br/>Les clients HTTP/1.1 peuvent aussi établir plusieurs connexions pour accélérer les téléchargements, et SSL nécessite des connexions séparées des connexions non SSL. Assurez-vous que la limite est correctement définie afin de ne pas affecter négativement le service normal. La limite recommandée se situe entre <span class=&quot;lst-inline-token lst-inline-token--value&quot;>5</span> et <span class=&quot;lst-inline-token lst-inline-token--value&quot;>10</span>.', ' Un nombre plus bas permettra de servir davantage de clients distincts.<br/> Les IP ou sous-réseaux de confiance ne sont pas affectés.<br/> Définissez une valeur élevée lorsque vous effectuez des tests de benchmark avec un grand nombre de machines clientes simultanées.', 'Nombre entier', '');

$_tipsdb['sslCert'] = new DAttrHelp("Cle privee SSL et certificat", 'Chaque listener SSL requiert une cle privee SSL et un certificat SSL associes. Plusieurs listeners SSL peuvent partager la meme cle et le meme certificat.<br/><br/>Vous pouvez generer vous-meme des cles privees SSL avec un paquet logiciel SSL, comme OpenSSL. Les certificats SSL peuvent aussi etre achetes aupres d&#039;une autorite de certification autorisee comme VeriSign ou Thawte. Vous pouvez aussi signer le certificat vous-meme. Les certificats autosignes ne seront pas approuves par les navigateurs web et ne doivent pas etre utilises sur des sites publics contenant des donnees critiques. Toutefois, un certificat autosigne suffit pour un usage interne, par exemple pour chiffrer le trafic vers la console WebAdmin de LiteSpeed Web Server.', '', '', '');

$_tipsdb['sslDefaultCiphers'] = new DAttrHelp("Suite de chiffrement par défaut", 'Suite de chiffrement par défaut pour les certificats SSL.<br/><br/>Valeur par défaut: valeur interne par défaut du serveur (basée sur les meilleures pratiques actuelles)', '', 'Chaîne de spécifications de chiffrement séparées par des deux-points.', '');

$_tipsdb['sslEnableMultiCerts'] = new DAttrHelp("Activer plusieurs certificats SSL", 'Permet aux listeners/vhosts de définir plusieurs certificats SSL. Si plusieurs certificats sont activés, les certificats/clés doivent suivre un schéma de nommage. Si le certificat est nommé server.crt, d’autres noms possibles sont server.crt.rsa, server.crt.dsa, server.crt.ecc. Si &quot;Not Set&quot;, la valeur par défaut est &quot;No&quot;.', '', 'Sélectionner avec les boutons radio', '');

$_tipsdb['sslOCSP'] = new DAttrHelp("OCSP Stapling", 'Online Certificate Status Protocol (OCSP) est une methode plus efficace pour verifier si un certificat numerique est valide. Il fonctionne en communiquant avec un autre serveur, l&#039;OCSP responder, afin d&#039;obtenir la verification que le certificat est valide au lieu de consulter les listes de revocation de certificats (CRL).<br/><br/>OCSP stapling est une amelioration supplementaire de ce protocole, permettant au serveur de verifier aupres de l&#039;OCSP responder a intervalles reguliers au lieu de le faire chaque fois qu&#039;un certificat est demande. Consultez la page Wikipedia <a href="http://en.wikipedia.org/wiki/OCSP_Stapling" target="_blank" rel="noopener noreferrer">OCSP</a> pour plus de details.', '', '', '');

$_tipsdb['sslOcspProxy'] = new DAttrHelp("Proxy OCSP", 'Adresse de socket utilisée comme adresse du serveur proxy pour la vérification OCSP. Laissez ce réglage non défini si vous n’utilisez pas de proxy.<br/><br/>Valeur par défaut: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>not set</span>', '', 'Adresse de socket', '');

$_tipsdb['sslProtocol'] = new DAttrHelp("Version du protocole", 'Selection de protocoles SSL acceptes par le listener.<br/><br/>Les options comprennent: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>SSL v3.0</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>TLS v1.0</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>TLS v1.1</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>TLS v1.2</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>TLS v1.3</span>.', '', 'Sélectionner avec des cases à cocher', '');

$_tipsdb['sslSessionCache'] = new DAttrHelp("Activer le cache de session", 'Active la mise en cache des ID de session avec le réglage par défaut d’OpenSSL. Le réglage de niveau serveur doit être défini sur &quot;Yes&quot; pour que le réglage Virtual Host prenne effet.<br/><br/>Valeurs par défaut:<br/><b>Niveau serveur:</b> Yes<br/><b>Niveau VH:</b> Yes', '', 'Sélectionner avec les boutons radio', '');

$_tipsdb['sslSessionCacheSize'] = new DAttrHelp("Taille du cache de session (octets)", 'Définit le nombre maximal d’ID de session SSL à stocker dans le cache. La valeur par défaut est 1,000,000.', '', 'Nombre entier', '');

$_tipsdb['sslSessionCacheTimeout'] = new DAttrHelp("Timeout du cache de session (s)", 'Cette valeur détermine combien de temps un ID de session restera valide dans le cache avant qu’une renégociation soit requise. La valeur par défaut est 3,600.', '', 'Nombre entier', '');

$_tipsdb['sslSessionTicketKeyFile'] = new DAttrHelp("Fichier de clé de ticket de session SSL", 'Permet à un administrateur de créer/maintenir la clé de ticket SSL. Le fichier doit faire 48 octets. Si cette option est laissée vide, le load balancer générera et fera tourner son propre jeu de clés.<br/><br/>IMPORTANT: Pour maintenir la forward secrecy, il est fortement recommandé de changer la clé toutes les <b>SSL Session Ticket Lifetime</b> secondes. Si cela ne peut pas être fait, il est recommandé de laisser ce champ vide.', '', 'Chemin', '');

$_tipsdb['sslSessionTicketLifetime'] = new DAttrHelp("Durée de vie du ticket de session SSL (s)", 'Cette valeur détermine combien de temps un ticket de session restera valide avant qu’une renégociation soit requise. La valeur par défaut est 3,600.', '', 'Nombre entier', '');

$_tipsdb['sslSessionTickets'] = new DAttrHelp("Activer les tickets de session", 'Active les tickets de session avec le réglage par défaut des tickets de session d’OpenSSL. Le réglage de niveau serveur doit être défini sur &quot;Yes&quot; pour que le réglage Virtual Host prenne effet.<br/><br/>Valeurs par défaut:<br/><b>Niveau serveur:</b> Yes<br/><b>Niveau VH:</b> Yes', '', 'Sélectionner avec les boutons radio', '');

$_tipsdb['sslStrictSni'] = new DAttrHelp("Certificat SNI strict", 'Spécifie s’il faut exiger strictement une configuration de certificat dédiée pour le virtual host. Lorsque cette option est activée, les connexions SSL aux virtual hosts sans configuration de certificat dédiée échoueront au lieu d’utiliser un certificat catch-all par défaut.<br/><br/>Valeur par défaut: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span>', '', 'Sélectionner avec les boutons radio', '');

$_tipsdb['sslStrongDhKey'] = new DAttrHelp("Clé DH forte SSL", 'Spécifie s’il faut utiliser des clés DH 2048 ou 1024 bits pour les handshakes SSL. Si défini sur &quot;Yes&quot;, des clés DH 2048 bits seront utilisées pour les clés et certificats SSL 2048 bits. Des clés DH 1024 bits seront toujours utilisées dans les autres situations. La valeur par défaut est &quot;Yes&quot;.<br/><br/>Les anciennes versions de Java ne prennent pas en charge les tailles de clé DH supérieures à 1024 bits. Si la compatibilité avec les clients Java est requise, ceci doit être défini sur &quot;No&quot;.', '', 'radio', '');

$_tipsdb['statDir'] = new DAttrHelp("Repertoire de sortie des statistiques", 'Le repertoire ou le fichier de rapport Real-Time Stats sera ecrit. Le repertoire par defaut est <b>/tmp/lshttpd/</b> .', 'Pendant le fonctionnement du serveur, le fichier .rtreport sera ecrit chaque seconde. Pour eviter les ecritures disque inutiles, definissez ceci sur un RAM Disk.<br/>Le fichier .rtreport peut etre utilise avec des logiciels de surveillance tiers pour suivre la sante du serveur.', 'Chemin absolu', '');

$_tipsdb['staticReqPerSec'] = new DAttrHelp("Requêtes statiques/seconde", 'Spécifie le nombre maximal de requêtes vers du contenu statique provenant d’une seule adresse IP qui peuvent être traitées en une seconde, quel que soit le nombre de connexions établies.<br/><br/>Lorsque cette limite est atteinte, toutes les requêtes suivantes sont retenues jusqu’à la seconde suivante. Les limites de requêtes pour le contenu généré dynamiquement sont indépendantes de cette limite. Les limites de requêtes par client peuvent être définies au niveau serveur ou virtual host. Les réglages de niveau virtual host remplacent les réglages de niveau serveur.', ' Les IP ou sous-réseaux de confiance ne sont pas affectés.', 'Nombre entier', '');

$_tipsdb['statuscode'] = new DAttrHelp("Code d’etat", 'Indique le code d’etat de reponse de la redirection externe. Si le code d’etat est entre 300 et 399, &quot;URI de destination&quot; peut etre indique.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['suexecGroup'] = new DAttrHelp("Groupe suEXEC", 'Au niveau du contexte actuel, executer avec ce groupe. <b>suEXEC User</b> au niveau de l&#039;hote virtuel, ou <b>Run As User</b> au niveau de l&#039;application externe, doit etre defini pour que <b>suEXEC Group</b> prenne effet.<br/><br/>Cette configuration peut etre remplacee au niveau de l&#039;application externe avec le parametre <b>Run As Group</b>.<br/><br/>Valeur par defaut: valeur du parametre <b>suExec User</b>', '', 'Nom de groupe ou uid valide', '');

$_tipsdb['suexecUser'] = new DAttrHelp("Utilisateur suEXEC", 'Au niveau du contexte actuel, executer avec cet utilisateur. Si elle est definie, cette valeur remplacera le parametre <b>ExtApp Set UID Mode</b> au niveau de l&#039;hote virtuel.<br/><br/>Cette configuration peut etre remplacee au niveau de l&#039;application externe avec le parametre <b>Run As User</b>.<br/><br/>Valeur par defaut: Non defini', '', 'Nom d&#039;utilisateur ou uid valide.', '');

$_tipsdb['suffix'] = new DAttrHelp("Suffixes", 'Spécifie les suffixes des fichiers de script qui seront gérés par ce gestionnaire de scripts. Les suffixes doivent être uniques.', 'Le serveur ajoute automatiquement un type MIME spécial (&quot;application/x-httpd-[suffix]&quot;) pour le premier suffixe de la liste. Par exemple, le type MIME &quot;application/x-httpd-php53&quot; sera ajouté pour le suffixe &quot;php53&quot;. Les suffixes suivants doivent être configurés dans les paramètres &quot;Parametres MIME&quot;.<br/>Même si ce champ liste des suffixes, les gestionnaires de scripts utilisent les types MIME, et non les suffixes, pour décider quels scripts gérer.<br/> Spécifiez uniquement les suffixes dont vous avez réellement besoin.', 'Liste séparée par des virgules; le caractère point &quot;.&quot; est interdit.', '');

$_tipsdb['swappingDir'] = new DAttrHelp("Repertoire de swapping", 'Indique le repertoire ou les fichiers de swapping doivent etre places. Lorsque le serveur demarre en mode chroot, ce repertoire est relatif au nouveau repertoire racine; sinon il est relatif au repertoire racine reel.<br/><br/>Le serveur utilise sa propre memoire virtuelle pour reduire l’utilisation de la memoire systeme. La memoire virtuelle et le disk swapping servent a stocker de grands corps de requete et des reponses generees dynamiquement. Le repertoire de swapping doit etre place sur un disque avec assez d’espace.<br/><br/>Valeur par defaut: /tmp/lshttpd/swap', ' Placez le repertoire de swapping sur un disque separe ou augmentez la taille du buffer E/S en memoire pour eliminer le swapping.', 'Chemin absolu', '');

$_tipsdb['templateFile'] = new DAttrHelp("Fichier de template", 'Indique le chemin du fichier de configuration de cette template. Le fichier doit se trouver dans $SERVER_ROOT/conf/templates/ avec un nom de fichier &quot;.conf&quot;. Si le fichier désigné n&#039;existe pas, après une tentative d&#039;enregistrement de la template, une erreur apparaîtra avec le lien &quot;CLICK TO CREATE&quot;. Ce lien générera un nouveau fichier de template vide. Lorsque vous supprimez la template, l&#039;entrée est retirée de vos configurations, mais le fichier de configuration réel de la template n&#039;est pas supprimé.', '', 'chemin', '');

$_tipsdb['templateName'] = new DAttrHelp("Nom de la template", 'Nom unique de la template.', '', '', '');

$_tipsdb['templateVHAliases'] = new DAttrHelp("Alias de domaine", 'Indique les autres noms de l&#039;hôte virtuel. Tous les hostnames et adresses IP possibles doivent être ajoutés à cette liste. Les caractères génériques <span class=&quot;lst-inline-token lst-inline-token--value&quot;>*</span> et <span class=&quot;lst-inline-token lst-inline-token--value&quot;>?</span> sont autorisés dans le nom. Ajoutez <span class=&quot;lst-inline-token lst-inline-token--value&quot;>:<port></span> pour les sites web qui ne sont pas sur le port 80.<br/><br/>Les alias seront utilisés dans les situations suivantes: <ol>   <li>Pour faire correspondre le hostname dans l&#039;en-tête Host lors du traitement d&#039;une requête.</li>   <li>Pour remplir les configurations de nom de domaine/alias pour des modules complémentaires comme FrontPage ou AWstats.</li>   <li>Pour configurer les mappages listener vers hôte virtuel basés sur la template d&#039;hôte virtuel.</li> </ol>', '', 'Liste de noms de domaine séparés par des virgules.', '');

$_tipsdb['templateVHConfigFile'] = new DAttrHelp("Fichier de configuration VHost instancié", 'Indique l&#039;emplacement du fichier de configuration généré lorsque vous instanciez un hôte virtuel membre. La variable <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_NAME</span> doit apparaître dans le chemin afin que chaque hôte virtuel ait son propre fichier. Il doit se trouver sous $SERVER_ROOT/conf/vhosts/. Ce fichier de configuration ne sera créé qu&#039;après avoir sorti un vhost membre de la template par instanciation.', '$VH_NAME/vhconf.conf est recommandé pour faciliter la gestion.', 'Chaîne avec la variable $VH_NAME et le suffixe .conf', '');

$_tipsdb['templateVHDocRoot'] = new DAttrHelp("Racine des documents", 'Indique le chemin unique de la racine des documents de chaque hôte virtuel membre. La variable <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_NAME</span> ou <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_ROOT</span> doit apparaître dans le chemin afin que chaque hôte virtuel membre ait sa propre racine des documents.', '', 'chemin avec la variable $VH_NAME ou $VH_ROOT', '$VH_ROOT/public_html/ ou $SERVER_ROOT/$VH_NAME/public_html.');

$_tipsdb['templateVHDomain'] = new DAttrHelp("Nom de domaine", 'Indique le nom de domaine principal de cet hôte virtuel membre. S&#039;il est laissé vide, le nom de l&#039;hôte virtuel sera utilisé. Il doit s&#039;agir d&#039;un nom de domaine pleinement qualifié, mais vous pouvez également utiliser une adresse IP. Il est recommandé d&#039;ajouter <span class=&quot;lst-inline-token lst-inline-token--value&quot;>:<port></span> pour les sites web qui ne sont pas sur le port 80. Pour les configurations contenant des noms de domaine, ce domaine peut être référencé avec la variable <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_DOMAIN</span>.<br/><br/>Ce nom de domaine sera utilisé dans les situations suivantes: <ol>   <li>Pour faire correspondre le hostname dans l&#039;en-tête Host lors du traitement d&#039;une requête.</li>   <li>Pour remplir les configurations de noms de domaine pour des modules complémentaires comme FrontPage ou AWstats.</li>  <li>Pour configurer les mappages listener vers hôte virtuel basés sur la template d&#039;hôte virtuel.</li> </ol>', '', 'nom de domaine', '');

$_tipsdb['templateVHName'] = new DAttrHelp("Nom de l'hôte virtuel", 'Nom unique de cet hôte virtuel. Ce nom doit être unique parmi tous les hôtes virtuels membres de template et les hôtes virtuels autonomes. Dans une configuration de chemin de répertoire, ce nom peut être référencé par la variable <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_NAME</span>.<br/><br/>Si un hôte virtuel autonome portant le même nom est également configuré, la configuration de l&#039;hôte virtuel membre sera ignorée.', '', '', '');

$_tipsdb['templateVHRoot'] = new DAttrHelp("Racine d'hôte virtuel par défaut", 'Indique le répertoire racine par défaut pour les hôtes virtuels membres utilisant cette template. La variable <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_NAME</span> doit apparaître dans le chemin. Cela permet d&#039;attribuer automatiquement à chaque membre de la template un répertoire racine distinct basé sur son nom.', '', 'chemin', '');

$_tipsdb['throttleBlockWindow'] = new DAttrHelp("Duree initiale de blocage (s)", 'Indique la duree initiale, en secondes, pendant laquelle un client est bloque apres avoir atteint le nombre maximal autorise d&#039;echecs de connexion. Valeur par defaut si non definie: 900 secondes.', 'Utilisez une duree assez longue pour decourager les attaques repetees sans imposer un temps de blocage excessif aux utilisateurs valides.', 'Nombre entier', '');

$_tipsdb['throttleEnabled'] = new DAttrHelp("Activer la limitation de connexion", 'Active la limitation des connexions pour la console WebAdmin. Lorsqu&#039;elle est activee, les tentatives de connexion echouees et repetees sont suivies et bloquees temporairement afin de reduire les attaques par force brute contre les mots de passe. Si seule cette option est activee et que les autres reglages de limitation restent vides, les valeurs par defaut integrees sont utilisees.', ' Gardez cette option activee en production, sauf si vous diagnostiquez des problemes de connexion. Lorsqu&#039;elle est activee sans valeurs personnalisees, les valeurs par defaut sont 5 echecs, 900 secondes de blocage initial et 14400 secondes de blocage maximum.', 'Sélectionner avec les boutons radio', '');

$_tipsdb['throttleMaxBackoff'] = new DAttrHelp("Duree maximale de blocage (s)", 'Indique la duree maximale de blocage, en secondes, lorsque les tentatives de connexion echouees continuent et que le backoff de limitation augmente. Valeur par defaut si non definie: 14400 secondes.', 'Definissez une limite superieure assez forte pour ralentir les attaques automatisees tout en permettant une recuperation dans un delai raisonnable.', 'Nombre entier', '');

$_tipsdb['throttleMaxFailures'] = new DAttrHelp("Echecs de connexion max.", 'Indique combien de tentatives de connexion echouees consecutives sont autorisees avant que le client soit bloque. Valeur par defaut si non definie: 5.', ' Des valeurs plus basses augmentent la protection, mais peuvent bloquer plus rapidement des utilisateurs legitimes.', 'Nombre entier', '');

$_tipsdb['toggleDebugLog'] = new DAttrHelp("Basculer la journalisation de débogage", 'Toggle Debug Logging bascule la valeur de &quot;Niveau de débogage&quot; entre <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span> et <span class=&quot;lst-inline-token lst-inline-token--value&quot;>HIGH</span>. Comme la journalisation de débogage affecte les performances et peut remplir rapidement le disque dur, &quot;Niveau de débogage&quot; doit généralement être défini sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span> sur un serveur de production. Cette fonction peut être utilisée pour activer ou désactiver rapidement la journalisation de débogage afin de diagnostiquer un problème sur un serveur de production. La journalisation de débogage activée ou désactivée de cette manière ne modifie rien dans les configurations affichées du serveur.', '&quot;Basculer la journalisation de débogage&quot; ne fonctionne que si &quot;Niveau de journalisation&quot; est défini sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span>.<br/> Important! La journalisation de débogage inclut des informations détaillées pour chaque requête et réponse. Une journalisation de débogage active dégrade fortement les performances du service et peut saturer l&#039;espace disque en très peu de temps. Cette fonction ne doit être utilisée que pendant une courte période lors du diagnostic de problèmes serveur.', '', '');

$_tipsdb['totalInMemCacheSize'] = new DAttrHelp("Taille totale du cache de petits fichiers (octets)", 'Spécifie la mémoire totale pouvant être allouée au cache de tampon afin de mettre en cache/servir de petits fichiers statiques.', '', 'Nombre entier', '');

$_tipsdb['totalMMapCacheSize'] = new DAttrHelp("Taille totale du cache MMAP (octets)", 'Spécifie la mémoire totale pouvant être allouée au cache mappé en mémoire afin de mettre en cache/servir des fichiers statiques de taille moyenne.', '', 'Nombre entier', '');

$_tipsdb['tp_vhFileName'] = new DAttrHelp("Nom de fichier utilisé dans la template", 'Indique un chemin de fichier utilisé par les réglages d&#039;hôtes virtuels basés sur une template. La variable <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_NAME</span> ou <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_ROOT</span> doit apparaître dans le chemin afin que chaque hôte virtuel membre pointe vers son propre fichier. Ce réglage concerne les fichiers appartenant à la template, comme les fichiers journaux, et non le fichier de configuration VHost instancié.', '', 'chemin avec la variable $VH_NAME ou $VH_ROOT', '');

$_tipsdb['umask'] = new DAttrHelp("umask", 'Définit l’umask par défaut pour les processus CGI. Voir <span class=&quot;lst-inline-token lst-inline-token--command&quot;> man 2 umask </span> pour plus de détails. Cela sert aussi de valeur par défaut pour &quot;umask&quot; des applications externes.', '', 'valeur dans la plage valide [000]-[777].', '');

$_tipsdb['uploadPassByPath'] = new DAttrHelp("Passer les donnees d’upload par chemin de fichier", 'Indique s’il faut ou non transmettre les donnees du fichier upload par chemin. Si active, le chemin du fichier avec d’autres informations est envoye au backend handler au lieu du fichier lui-meme lors de l’upload. Cela economise des ressources CPU et du temps de transfert, mais demande des mises a jour cote backend pour l’implementation. Si desactive, le contenu du fichier sera transfere au backend handler; le corps de requete reste parse en fichiers.', ' Activez ceci pour accelerer le traitement des uploads de fichiers si la compatibilite ascendante n’est pas un probleme.', 'Sélectionner avec les boutons radio', '');

$_tipsdb['uploadTmpDir'] = new DAttrHelp("Chemin des fichiers temporaires", 'Répertoire temporaire où les fichiers envoyés au serveur seront stockés pendant que l’analyseur du corps de requête fonctionne. La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/tmp/lshttpd/</span>.', '', 'Chemin absolu ou chemin commençant par $SERVER_ROOT (pour les niveaux serveur et VHost) ou $VH_ROOT (pour les niveaux VHost).', '');

$_tipsdb['uploadTmpFilePermission'] = new DAttrHelp("Permission de fichier temporaire", 'Détermine les permissions de fichier utilisées pour les fichiers stockés dans le répertoire temporaire. Le réglage au niveau serveur est global et peut être remplacé au niveau VHost.', '', 'Nombre octal à 3 chiffres. La valeur par défaut est 666.', '');

$_tipsdb['uri'] = new DAttrHelp("URI", 'Indique l’URI de ce contexte. L’URI doit commencer par &quot;/&quot;. Si une URI se termine par &quot;/&quot;, ce contexte inclura toutes les sous-URI sous cette URI.', '', 'URI', '');

$_tipsdb['useAIO'] = new DAttrHelp("Utiliser l’I/O asynchrone (AIO)", 'Spécifie s’il faut utiliser l’I/O asynchrone pour servir les fichiers statiques, ainsi que l’implémentation AIO à utiliser. Les options <span class=&quot;lst-inline-token lst-inline-token--value&quot;>LINUX AIO</span> et <span class=&quot;lst-inline-token lst-inline-token--value&quot;>io_uring</span> ne sont disponibles que sur les machines Linux.<br/><br/>Valeur par défaut: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span>', ' AIO peut aider à améliorer les performances sur les serveurs avec une forte attente I/O.<br/> Lorsque <span class=&quot;lst-inline-token lst-inline-token--value&quot;>io_uring</span> est sélectionné mais non pris en charge sur la machine actuelle, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Linux AIO</span> sera utilisé à la place.', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['useIpInProxyHeader'] = new DAttrHelp("Utiliser l’IP client dans l’en-tete", 'Indique s’il faut utiliser la premiere adresse IP la plus valide listee dans l’en-tete de requete HTTP &quot;X-Forwarded-For&quot; pour toutes les fonctions liees aux adresses IP, y compris le throttling de connexion/bande passante, le controle d’acces et la geolocalisation IP.<br/><br/>Cette fonction est utile si votre serveur web se trouve derriere un load balancer ou un serveur proxy. Si vous selectionnez <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Trusted IP Only</span>, l’IP X-Forwarded-For sera utilisee uniquement lorsque la requete provient d’IPs de confiance definies dans &quot;Liste autorisée&quot; au niveau serveur.<br/><br/><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Keep Header from Trusted IP</span> est identique a <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Trusted IP Only</span>, mais l’en-tete X-Forwarded-For utilise pour le backend ne sera pas modifie pour inclure l’adresse du pair connecte.<br/><br/><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Use Last IP (for AWS ELB)</span> utilisera la derniere adresse IP de la liste &quot;X-Forwarded-For&quot;. Selectionnez cette option si vous utilisez AWS Elastic Load Balancer ou si vous vous attendez a ce que l’IP reelle soit ajoutee a la fin de la liste &quot;X-Forwarded-For&quot;.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['useSendfile'] = new DAttrHelp("Utiliser sendfile()", 'Spécifie s’il faut utiliser l’appel système sendfile() pour servir les fichiers statiques. Les fichiers statiques peuvent être servis de quatre façons différentes: cache de tampon mémoire, cache mappé en mémoire, lecture/écriture simple et sendfile(). Les fichiers plus petits que &quot;Taille max. de petit fichier en cache (octets)&quot; sont servis depuis le cache de tampon mémoire. Les fichiers plus grands que &quot;Taille max. de petit fichier en cache (octets)&quot; mais plus petits que &quot;Taille max. de fichier MMAP (octets)&quot; seront servis depuis le cache mappé en mémoire. Les fichiers plus grands que &quot;Taille max. de fichier MMAP (octets)&quot; seront servis via lecture/écriture simple ou sendfile(). Sendfile() est un appel système &quot;zero copy&quot; qui peut réduire fortement l’utilisation CPU lors du service de très gros fichiers statiques. Sendfile() nécessite un pilote noyau de carte réseau optimisé et peut donc ne pas convenir à certains adaptateurs réseau de petits fournisseurs.', '', 'Sélectionner avec les boutons radio', '');

$_tipsdb['userDBCacheTimeout'] = new DAttrHelp("Timeout du cache de DB utilisateur (s)", 'Indique la frequence a laquelle la base de donnees utilisateur backend sera verifiee pour detecter des changements. Chaque entree du cache possede un horodatage. Lorsque les donnees mises en cache sont plus anciennes que le timeout indique, la base de donnees backend sera verifiee. S’il n’y a pas de changement, l’horodatage sera reinitialise a l’heure actuelle; sinon les nouvelles donnees seront chargees. Le rechargement du serveur et le graceful restart videront le cache immediatement.', ' Si la base de donnees backend ne change pas souvent, definissez un timeout plus long pour de meilleures performances.', 'Nombre entier', '');

$_tipsdb['userDBLocation'] = new DAttrHelp("Emplacement de la DB utilisateur", 'Indique l’emplacement de la base de donnees utilisateur. Il est recommande de stocker la base de donnees sous le repertoire $SERVER_ROOT/conf/vhosts/$VH_NAME/.<br/><br/>Pour le type de DB <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Password File</span>, il s’agit du chemin vers le fichier plat contenant les definitions utilisateur/mot de passe. Vous pouvez modifier ce fichier via la console WebAdmin en cliquant sur le nom du fichier.<br/><br/>Chaque ligne du fichier utilisateur contient un nom d’utilisateur suivi de deux-points, puis d’un mot de passe chiffre par crypt(), eventuellement suivi de deux-points et des noms de groupe auxquels l’utilisateur appartient. Les noms de groupe sont separes par des virgules. Si les informations de groupe sont indiquees dans la base de donnees utilisateur, la base de donnees groupe ne sera pas verifiee.<br/><br/>Exemple:<blockquote><code>john:HZ.U8kgjnMOHo:admin,user</code></blockquote>', '', 'Chemin vers le fichier de DB utilisateur.', '');

$_tipsdb['userDBMaxCacheSize'] = new DAttrHelp("Taille maximale du cache de DB utilisateur", 'Indique la taille maximale du cache de la base de donnees utilisateur. Les donnees d’authentification utilisateur recemment consultees seront mises en cache en memoire afin de fournir des performances maximales.', ' Comme un cache plus grand consommera plus de memoire, une valeur plus elevee peut ou non fournir de meilleures performances. Definissez une taille appropriee selon la taille de votre base de donnees utilisateur et l’utilisation du site.', 'Nombre entier', '');

$_tipsdb['uwsgiContext'] = new DAttrHelp("Contexte uWSGI", 'Les applications uWSGI ne peuvent pas etre utilisees directement. Une application uWSGI doit etre configuree comme gestionnaire de scripts ou associee a une URL au moyen d&#039;un contexte uWSGI. Un contexte uWSGI associe une URI a une application uWSGI.', '', '', '');

$_tipsdb['uwsgiapp'] = new DAttrHelp("Application uWSGI", 'Indique le nom de l’application uWSGI. Cette application doit etre definie dans la section &quot;Applications externes&quot; au niveau serveur ou hote virtuel.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['vaction'] = new DAttrHelp("Actions - Hôte virtuel", 'Ce champ affiche des boutons pour désactiver, activer ou redémarrer l&#039;hôte virtuel. Les actions effectuées sur un hôte virtuel n&#039;affectent pas le reste du serveur web.', 'Il est conseillé de désactiver temporairement un hôte virtuel lors de la mise à jour de son contenu.', '', '');

$_tipsdb['vdisable'] = new DAttrHelp("Désactiver", 'L&#039;action <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Disable</span> arrête un hôte virtuel en cours d&#039;exécution. Les nouvelles requêtes ne seront pas acceptées, mais les requêtes en cours seront terminées normalement.', '', '', '');

$_tipsdb['venable'] = new DAttrHelp("Activer", 'L&#039;action <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Enable</span> démarre un hôte virtuel arrêté. Cela permet d&#039;accepter de nouvelles requêtes.', '', '', '');

$_tipsdb['verifyDepth'] = new DAttrHelp("Profondeur de verification", ' Indique jusqu’a quelle profondeur un certificat doit etre verifie avant de determiner que le client n’a pas de certificat valide. La valeur par defaut est &quot;1&quot;.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['vhEnableBr'] = new DAttrHelp("Activer la compression Brotli", 'Indique s’il faut activer la compression Brotli pour cet hôte virtuel. Ce réglage ne prend effet que lorsque &quot;Niveau de compression Brotli (fichier statique)&quot; est défini sur une valeur non nulle au niveau serveur.', '', 'Sélectionner avec les boutons radio', '');

$_tipsdb['vhEnableGzip'] = new DAttrHelp("Activer la compression", 'Indique s’il faut activer la compression GZIP pour cet hôte virtuel. Ce réglage ne prend effet que lorsque &quot;Activer la compression&quot; est défini sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span> au niveau serveur.', '', 'Sélectionner avec les boutons radio', '');

$_tipsdb['vhEnableQuic'] = new DAttrHelp("Activer HTTP3/QUIC", 'Active le protocole réseau HTTP3/QUIC pour cet hôte virtuel. Pour que ce réglage prenne effet, &quot;Activer HTTP3/QUIC&quot; et &quot;Ouvrir le port HTTP3/QUIC (UDP)&quot; doivent aussi être définis sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span> aux niveaux serveur et listener respectivement. La valeur par défaut est <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>.', 'Lorsque ce réglage est défini sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span>, l’annonce HTTP3/QUIC ne sera plus envoyée. Si un navigateur contient encore des informations HTTP3/QUIC en cache et que HTTP3/QUIC est toujours activé aux niveaux serveur et listener, une connexion HTTP3/QUIC continuera d’être utilisée jusqu’à ce que ces informations ne soient plus en cache ou qu’une erreur de protocole HTTP3/QUIC soit rencontrée.', 'Sélectionner avec les boutons radio', '');

$_tipsdb['vhMaxKeepAliveReq'] = new DAttrHelp("Requetes Keep-Alive maximales", 'Indique le nombre maximal de requetes pouvant etre servies via une connexion keep-alive (persistante). Les connexions seront fermees lorsque cette limite sera atteinte. Vous pouvez indiquer une limite differente pour chaque hote virtuel. Ce nombre ne peut pas depasser la limite de niveau serveur &quot;Requêtes Keep-Alive max.&quot;.', ' Definissez une valeur raisonnablement elevee. Une valeur de &quot;1&quot; ou moins desactivera les connexions keep-alive.', 'Nombre entier', '');

$_tipsdb['vhModuleUrlFilters'] = new DAttrHelp("Filtres URL de module", 'C&#039;est un emplacement centralise permettant de personnaliser les parametres des modules pour les contextes d&#039;hote virtuel. Les parametres d&#039;une URI de contexte remplacent les parametres de niveau hote virtuel ou serveur.', '', '', '');

$_tipsdb['vhModules'] = new DAttrHelp("Modules d'hôte virtuel", 'Les donnees de configuration des modules de l&#039;hote virtuel sont, par defaut, heritees de la configuration des modules du serveur. Les modules de l&#039;hote virtuel sont limites aux hooks de niveau HTTP.', '', '', '');

$_tipsdb['vhName'] = new DAttrHelp("Nom de l'hote virtuel", 'Nom unique d&#039;un hote virtuel. Il est recommande d&#039;utiliser le nom de domaine de l&#039;hote virtuel comme nom d&#039;hote virtuel. Le nom d&#039;hote virtuel peut etre reference avec la variable $VH_NAME.', '', '', '');

$_tipsdb['vhRoot'] = new DAttrHelp("Racine de l'hote virtuel", 'Indique le repertoire racine de l&#039;hote virtuel. Remarque: ce n&#039;est <b>PAS</b> la racine des documents. Il est recommande de placer tous les fichiers lies a l&#039;hote virtuel (comme les fichiers journaux, les fichiers html, les scripts CGI, etc.) dans ce repertoire. La racine de l&#039;hote virtuel peut etre referencee avec la variable $VH_ROOT.', ' Placez les differents hotes virtuels sur des disques differents.', 'Un chemin absolu ou un chemin relatif à $SERVER_ROOT.', '');

$_tipsdb['vhaccessLog_fileName'] = new DAttrHelp("Nom du fichier", 'Nom du fichier journal d&#039;accès.', ' Placez le fichier journal d&#039;accès sur un disque séparé.', 'Nom de fichier pouvant être un chemin absolu ou un chemin relatif à $SERVER_ROOT, $VH_ROOT.', '');

$_tipsdb['vhadminEmails'] = new DAttrHelp("E-mail de l'administrateur", 'Indique les adresses e-mail des administrateurs de cet hôte virtuel.', '', 'Liste d&#039;adresses e-mail séparées par des virgules', '');

$_tipsdb['vhlog_fileName'] = new DAttrHelp("Nom du fichier", 'Spécifie le chemin du fichier journal.', ' Placez le fichier journal sur un disque séparé.', 'Nom de fichier pouvant être un chemin absolu ou un chemin relatif à $SERVER_ROOT, $VH_ROOT.', '');

$_tipsdb['vhlog_logLevel'] = new DAttrHelp("Niveau de journalisation", 'Spécifie le niveau de journalisation. Les niveaux disponibles (du plus élevé au plus bas) sont <span class=&quot;lst-inline-token lst-inline-token--value&quot;>ERROR</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>WARNING</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NOTICE</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>INFO</span> et <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span>. Seuls les messages dont le niveau est supérieur ou égal au paramètre actuel seront journalisés. Si vous voulez le définir sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span>, vous devez également définir le niveau de journalisation du serveur sur <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span>. Le niveau de débogage est contrôlé uniquement au niveau serveur par &quot;Niveau de débogage&quot;.', ' Sauf si &quot;Niveau de débogage&quot; est défini sur un niveau autre que <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span>, le niveau de journalisation <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span> n&#039;a pas d&#039;impact sur les performances et est recommandé.', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['viewlog'] = new DAttrHelp("Visualiseur du journal du serveur", 'Le visualiseur du journal du serveur est un outil pratique pour parcourir le journal actuel du serveur afin de rechercher des erreurs ou des problèmes. Le visualiseur de journaux parcourt le fichier journal du serveur par blocs selon le niveau de journalisation spécifié.<br/><br/>La taille de bloc par défaut est 20KB. Vous pouvez utiliser les boutons <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Begin</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>End</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Next</span> et <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Prev</span> pour naviguer dans un grand fichier journal.', 'La taille d&#039;une page générée dynamiquement est limitée par &quot;Taille max. du corps de réponse dynamique (octets)&quot;. Si le bloc est trop grand, la page peut être tronquée.', '', '');

$_tipsdb['virtualHostMapping'] = new DAttrHelp("Mappages des hôtes virtuels", 'Indique la relation entre le listener et les hotes virtuels. Les listeners et les hotes virtuels sont associes par noms de domaine. Une requete HTTP sera routee vers un hote virtuel dont le nom de domaine correspond. Un listener peut etre mappe vers plusieurs hotes virtuels pour differents noms de domaine. Un hote virtuel peut aussi etre mappe depuis differents listeners. Un listener peut autoriser un hote virtuel catchall avec la valeur de nom de domaine &quot;*&quot;. Lorsqu&#039;aucun nom de domaine ne correspond explicitement dans le mappage du listener, le listener transmettra la requete a cet hote virtuel catchall.', ' Ajoutez uniquement les mappages necessaires. Si le listener est mappe a un seul hote virtuel, configurez seulement un mappage catchall &quot;*&quot;.', '', '');

$_tipsdb['virtualHostName'] = new DAttrHelp("Hote virtuel", 'Indique le nom d&#039;un hote virtuel.', '', 'Sélectionner dans la liste déroulante', '');

$_tipsdb['vname'] = new DAttrHelp("Nom - Hôte virtuel", 'Nom unique qui identifie cet hôte virtuel. Il s&#039;agit du &quot;Nom de l&#039;hote virtuel&quot; que vous avez spécifié lors de la configuration de cet hôte virtuel.', '', '', '');

$_tipsdb['vreload'] = new DAttrHelp("Redémarrer - Hôte virtuel", 'L&#039;action Restart demande au serveur web de charger la configuration la plus récente pour cet hôte virtuel. Les requêtes en cours se termineront avec l&#039;ancienne configuration. La nouvelle configuration ne s&#039;appliquera qu&#039;aux nouvelles requêtes. Tous les changements d&#039;un hôte virtuel peuvent être appliqués à chaud de cette manière.', '', '', '');

$_tipsdb['vstatus'] = new DAttrHelp("État - Hôte virtuel", 'État actuel d&#039;un hôte virtuel. L&#039;état peut être: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Running</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Stopped</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Restart Required</span> ou <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Running - Removed from Configuration</span>.  <ul>     <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Running</span> signifie que l&#039;hôte virtuel est chargé et en service.</li>     <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Stopped</span> signifie que l&#039;hôte virtuel est chargé mais pas en service (désactivé).</li>     <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;> Restart Required</span> signifie qu&#039;il s&#039;agit d&#039;un hôte virtuel récemment ajouté et que le serveur n&#039;a pas encore chargé sa configuration.</li>     <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Running - Removed from Configuration</span> signifie que l&#039;hôte virtuel a été supprimé de la configuration du serveur, mais qu&#039;il est toujours en service.</li> </ul>', '', '', '');

$_tipsdb['wsaddr'] = new DAttrHelp("Adresse", 'Adresse de socket unique utilisée par le backend WebSocket. Les sockets IPv4, les sockets IPv6 et les Unix Domain Sockets (UDS) sont pris en charge. Les sockets IPv4 et IPv6 peuvent être utilisés pour la communication sur le réseau. UDS ne peut être utilisé que lorsque le backend WebSocket réside sur la même machine que le serveur.', ' Si le backend WebSocket fonctionne sur la même machine, UDS est préférable. Si vous devez utiliser un socket IPv4 ou IPv6, définissez l’adresse IP sur localhost ou 127.0.0.1 afin que le backend WebSocket soit inaccessible depuis d’autres machines.<br/> Les Unix Domain Sockets offrent généralement de meilleures performances que les sockets IPv4 ou IPv6.', 'adresse IPv4/IPv6:port, UDS://chemin, ou unix:chemin', '127.0.0.1:5434<br/>UDS://tmp/lshttpd/php.sock<br/>unix:/tmp/lshttpd/php.sock');

$_tipsdb['wsgiBin'] = new DAttrHelp("Chemin WSGI", 'Chemin vers l&#039;exécutable LiteSpeed Python Web Server Gateway Interface (lswsgi).<br/><br/>Cet exécutable est créé en compilant Python avec le module WSGI LSAPI de LiteSpeed.', '', 'Chemin absolu', '');

$_tipsdb['wsgiDefaults'] = new DAttrHelp("Reglages par defaut Python WSGI", 'Configurations par defaut pour les applications Python WSGI. Ces reglages peuvent etre remplaces au niveau du contexte.', '', '', '');

